var mm_ch_2_Verses = [
  {num:1,words:[["Ma sa oo i lena lava tausaga, sa toe amata ona i ai o se taua i le va o sa Nifaē ma sa Lamanā.", "And it came to pass in that same year there began to be a war again between the Nephites and the Lamanites."], ["Ma e ui ina sa ou talavou,", "And notwithstanding I being young,"], ["sa ou tino ese;", "was large in stature;"], ["o lea na tofia ai au e le nuu o Nifae ia avea au ma o latou taitai,", "therefore the people of Nephi appointed me that I should be their leader,"], ["po o le taitai o a latou autau.", "or the leader of their armies."]]},
  {num:2,words:[["O lea sa oo ai i le sefulu ma le ono o ou tausaga na ou alu atu ai e taimua i se autau a sa Nifaē,", "Therefore it came to pass that in my sixteenth year I did go forth at the head of an army of the Nephites,"], ["e faasaga ia sa Lamanā;", "against the Lamanites;"], ["o lea ua mavae atu le tolu selau luasefulu ma le ono tausaga.", "therefore three hundred and twenty and six years had passed away."]]},
  {num:3,words:[["Ma sa oo i le tausaga e tolu selau luasefulu ma le fitu na o mai ai sa Lamanā i luga o i matou ma le malosi tele lava,", "And it came to pass that in the three hundred and twenty and seventh year the Lamanites did come upon us with exceedingly great power,"], ["sa oo ina latou faamatatauina au autau;", "insomuch that they did frighten my armies;"], ["o lea sa latou le mananao ai e tau,", "therefore they would not fight,"], ["ma amata ona latou solomuli agai i laueleele i matu.", "and they began to retreat towards the north countries."]]},
  {num:4,words:[["Ma sa oo ina matou tau atu i le aai o Anekala,", "And it came to pass that we did come to the city of Angola,"], ["ma sa matou pulea le aai,", "and we did take possession of the city,"], ["ma faia sauniuniga e puipuia ai i matou lava e faasaga ia sa Lamanā. Ma sa oo ina matou tuioloina le aai e tusa ma lo matou malosi;", "and make preparations to defend ourselves against the Lamanites. And it came to pass that we did fortify the city with our might;"], ["peitai e ui ia matou tuiologa uma ae sa o mai lava sa Lamanā i o matou luga ma tutuli ese i matou i fafo mai le aai.", "but  notwithstanding all our fortifi– cations the Lamanites did come upon us and did drive us out of the city."]]},
  {num:5,words:[["Ma sa latou tutuli ese foi i matou i fafo mai le laueleele o Tavita.", "And they did also drive us forth out of the land of David."]]},
  {num:6,words:[["Ma sa matou savavali atu ma o atu i le laueleele o Iosua,", "And we marched forth and came to the land of Joshua,"], ["lea sa i ai i tuaoi i sisifo i tafatafa ane o le matafaga.", "which was in the borders west by the seashore."]]},
  {num:7,words:[["Ma sa oo ina matou faapotopoto o matou tagata i le vave sa mafai ona faia ai,", "And it came to pass that we did gather in our people as fast as it were possible,"], ["ina ia mafai ona matou faapotopoto faatasi i latou i se tino e tasi.", "that we might get them together in one body."]]},
  {num:8,words:[["Ae faauta,", "But behold,"], ["sa tumu le laueleele i faomea ma sa Lamanā;", "the land was filled with robbers and with Lamanites;"], ["ma e ui i le faafanoga tele sa tautau ifo i luga o lou nuu,", "and notwithstanding the great destruction which hungover my people,"], ["sa latou le salamo ia latou mea leaga;", "they did not repent of their evil doings;"], ["o lea na fola ai le laueleele atoa i le toto ma le tagata oti,", "therefore there was blood and carnage spread throughout all the face of the land,"], ["i le vaega a sa Nifaē ma le vaega foi a sa Lamanā;", "both on the part of the Nephites and also on the part of the Lamanites;"], ["ma o se fouvalega atoa lea e tasi sa i ai i luga o le laueleele atoa.", "and it was one complete revolution throughout all the face of the land."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["sa i ai se tupu o sa Lamanā,", "the Lamanites had a king,"], ["ma o lona igoa o Arona;", "and his name was Aaron;"], ["ma sa ia sau e faasaga mai ia te i matou ma se autau e fasefulu ma le fa afe.", "and he came against us with an army of forty and four thousand."], ["Ma faauta,", "And behold,"], ["sa ou tutetee atu ia te ia ma se autau e fasefulu ma le lua afe.", "I withstood him with forty and two thousand."], ["Ma sa oo ina ou faatoilaloina o ia faatasi ma lau autau, sa oo ina sola o ia mai ou luma.", "And it came to pass that I beat him with my army that he fled before me."], ["Faauta foi,", "And behold,"], ["o nei mea uma sa faia,", "all this was done,"], ["ma ua mavae atu le tolu selau ma le tolugafulu o tausaga.", "and three hundred and thirty years had passed away."]]},
  {num:10,words:[["Ma sa oo ina amata ona salamo sa Nifaē i lo latou amioletonu,", "And it came to pass that the Nephites began to repent of their iniquity,"], ["ma amata ona oi e pei lava ona sa valoia e Samuelu le perofeta;", "and began to cry even as had been prophesied by Samuel the prophet;"], ["aua faauta,", "for behold no man could keep that which was his own,"], ["sa le mafai e se tagata ona taofi o ana lava mea,", "for the thieves,"], ["ona o gaoi, ma faomea,", "and the robbers,"], ["ma tagata fasioti tagata,", "and the murderers,"], ["ma tagata fai mea faamaneta,", "and the magic art,"], ["ma faataulaitu sa i ai i le laueleele.", "and the witchcraft which was in the land."]]},
  {num:11,words:[["Sa faapea ona amata ona i ai o le faanoanoa ma le tagiauē i le laueleele atoa ona o nei mea,", "Thus there began to be a mourning and a lamentation in all the land because of these things,"], ["ma sa sili atu lava ona faapitoa i le nuu o Nifae.", "and more especially among the people of Nephi."]]},
  {num:12,words:[["Ma sa oo ina ua vaai atu au,", "And it came to pass that when I,"], ["o Mamona,", "Mormon,"], ["i lo latou tagiauē ma lo latou faavauvau ma lo latou faanoanoa i luma o le Alii, sa amata ona olioli o lou loto i totonu ia te au,", "saw their lamentation and their mourning and their sorrow before the Lord,"], ["i lou iloa o le alofa mutimutivale ma le tali-tiga o le Alii,", "my heart did begin to rejoice within me,"], ["o lea na ou manatu ai o le a ia alofa mutimutivale mai ia te i latou,", "knowing the mercies and the long– suffering of the Lord,"], ["ina ia toe avea i latou ma ni tagata amiotonu.", "therefore supposing that he would be merciful unto them that they would again become a righteous people."]]},
  {num:13,words:[["Ae faauta,", "But behold this my joy was vain,"], ["sa le aoga lou olioli,", "for their sorrowing was not unto repentance,"], ["ona o lo latou faanoanoa sa le tupu mai i le salamo, ona o le agalelei o le Atua;", "because of the goodness of God;"], ["ae o se faanoanoa o tagata tausalaina ,", "but it was rather the sorrowing of the damned,"], ["ona e le tuua pea i latou e le Alii i taimi uma ia latou fiafia i le agasala.", "because the Lord would not always suffer them to take happiness in sin."]]},
  {num:14,words:[["Ma sa latou le o mai ia Iesu ma le loto momomo ma le agaga salamo,", "And they did not come unto Jesus with broken hearts and contrite spirits,"], ["ae sa latou upuleaga i le Atua,", "but they did curse God,"], ["ma fia feoti. E ui i lea o le a latou tau ma le pelu mo o latou ola.", "and wish to die. Nevertheless they would struggle with the sword for their lives."]]},
  {num:15,words:[["Ma sa oo ina toe foi mai lou faanoanoa ia te au,", "And it came to pass that my sorrow did return unto me again,"], ["ma sa ou vaai ua mavae atu o le aso o le alofa tunoa mai ia te i latou,", "and I saw that the day of grace  was passed with them,"], ["faaletino ma faaleagaga;", "both temporally and spiritually;"], ["ona sa ou vaai i afe o i latou ua sala i lalo i le fouvale faaaliali e faasaga i lo latou Atua,", "for I saw thousands of them hewn down in open rebellion against their God,"], ["ma ua faulalai i luga o le laueleele e pei o ano. Ma ua faapea ona mavae atu le tolu selau fasefulu ma le fa o tausaga.", "and heaped up as dung upon the face of the land. And thus three hundred and forty and four years had passed away."]]},
  {num:16,words:[["Ma sa oo i le tausaga e tolu selau fasefulu ma le lima,", "And it came to pass that in the three hundred and forty and fifth year the Nephites did begin to flee before the Lamanites;"], ["sa amata ona sosola o sa Nifaē mai luma o sa Lamanā; ma sa tuliloaina i latou seia oo ina latou o mai i le laueleele o Iasona,", "and they were pursued until they came even to the land of Jashon,"], ["ae faatoa mafai ona taofi o i latou mai la latou solaaga.", "before it was possible to stop them in their retreat."]]},
  {num:17,words:[["Ma o lenei,", "And now,"], ["o le aai o Iasona sa latalata ane i le laueleele lea sa teu ai e Amorona talafaamaumau mo le Alii,", "the city of Jashon was near the land where Ammaron had deposited the records unto the Lord,"], ["ina ia le faaumatiaina. Ma faauta sa ou alu atu e tusa ma le upu a Amorona,", "that they might not be destroyed. And behold I had gone according to the word of Ammaron,"], ["ma ave papatusi a Nifae,", "and taken the plates of Nephi,"], ["ma ou faia se talafaamaumau e tusa ma upu a Amorona.", "and did make a record according to the words of Ammaron."]]},
  {num:18,words:[["Ma o luga o papatusi a Nifae na ou faia ai se tala atoa o le amioleaga ma mea inosia uma;", "And upon the plates of Nephi I did make a full account of all the wickedness and abominations;"], ["ae o luga o papatusi nei sa ou le faia ai se tala atoa o lo latou amioleaga ma mea inosia,", "but upon these plates I did forbear to make a full account of their wickedness and abominations,"], ["aua faauta, sa i luma o ou mata talu mai le taimi na mafai ai ona ou vaai i ala o le tagata,", "for behold,"], ["se vaaiga faaauau pea o le amioleaga ma mea inosia.", "a continual scene of wickedness and abominations has been before mine eyes ever since I have been sufficient to behold the ways of man."]]},
  {num:19,words:[["Ma auoi, ita e,", "And wo is me because of their wickedness;"], ["ona o lo latou amioleaga;", "for my heart has been filled with sorrow because of their wickedness,"], ["ona ua tumu lou loto i le faanoanoa, i ou aso uma,", "all my days;"], ["ona o lo latou amioleaga;", "nevertheless,"], ["e ui i lea, ua ou iloa o le a sii ae au i luga i le aso gataaga.", "I know that I shall be lifted up at the last day."]]},
  {num:20,words:[["Ma sa oo ina toe sailia ma tulia tagata o Nifae i le tausaga lenei. Ma sa oo ina tutulia i matou seia oo ina matou oo mai i le laueleele i matu sa taua o Semu.", "And it came to pass that in this year the people of Nephi again were hunted and driven. And it came to pass that we were driven forth until we had come northward to the land which was called Shem."]]},
  {num:21,words:[["Ma sa oo ina matou tuiolo aai o Semu,", "And it came to pass that we did fortify the city of Shem,"], ["ma sa matou faapotopotoina o matou tagata i le tele sa mafai ona faia ai,", "and we did gather in our people as much as it were possible,"], ["ina atonu e mafai ai ona matou faasaoina i latou mai le faaumatiaina.", "that perhaps we might save them from destruction."]]},
  {num:22,words:[["Ma sa oo i le tausaga e tolu selau fasefulu ma le ono, sa amata ona latou toe o mai i luga ia i matou.", "And it came to pass in the three hundred and forty and sixth year they began to come upon us again."]]},
  {num:23,words:[["Ma sa oo ina ou tautala atu i ou tagata,", "And it came to pass that I did speak unto my people,"], ["ma uunai atu ia te i latou ma le malosi tele,", "and did urge them with great energy,"], ["ia latou tutu atu ma le totoa i luma o sa Lamanā ma tau mo a latou ava,", "that they would stand boldly before the Lamanites and fight for their wives,"], ["ma a latou fanau,", "and their children,"], ["ma o latou fale,", "and their houses,"], ["ma o latou aiga.", "and their homes."]]},
  {num:24,words:[["Ma sa faaosoina i latou i le malosi teisi i au upu,", "And my words did arouse them somewhat to vigor,"], ["sa oo ina latou le sosola mai luma o sa Lamanā,", "insomuch that they did not flee from before the Lamanites,"], ["ae sa tutu atu ma le totoa e faasaga ia te i latou.", "but did stand with boldness against them."]]},
  {num:25,words:[["Ma sa oo ina matou tau ma se autau e tolusefulu afe e faasaga i se autau e limasefulu afe. Ma sa oo ina matou tutu atu i o latou luma ma le mausali tele sa oo ina latou sosola mai o matou luma.", "And it came to pass that we did contend with an army of thirty thousand against an army of fifty thousand. And it came to pass that we did stand before them with such firmness that they did flee from before us."]]},
  {num:26,words:[["Ma sa oo ina ua latou sosola,", "And it came to pass that when they had fled we did pursue them with our armies,"], ["sa matou tuliloa i latou faatasi ma a matou autau,", "and did meet them again,"], ["ma matou toe fetaiai ma i latou,", "and did beat them;"], ["ma faatoilalo i latou;", "nevertheless the strength of the Lord was not with us;"], ["e ui i lea sa le faatasi le malosi o le Alii ma i matou; ioe,", "yea,"], ["sa tuu i matou ia i matou lava,", "we were left to ourselves,"], ["sa lei mafuta le Agaga o le Alii ia te i matou;", "that the Spirit of the Lord did not abide in us;"], ["o lea na matou vaivai ai e pei o o matou uso.", "therefore we had become weak like unto our brethren."]]},
  {num:27,words:[["Ma sa faanoanoa lou loto ona o lenei malaia tele o lou nuu,", "And my heart did sorrow because of this the great calamity of my people,"], ["ona o lo latou amioleaga ma a latou mea inosia. Ae faauta,", "because of their wickedness and their abominations. But behold,"], ["sa matou o atu e faasaga ia sa Lamanā ma le au faomea a Katianetona,", "we did go forth against the Lamanites and the robbers of Gadianton,"], ["seia oo ina matou toe maua laueleele o o matou tofi.", "until we had again taken possession of the lands of our inheritance."]]},
  {num:28,words:[["Ma ua mavae atu le tausaga e tolu selau fasefulu ma le iva.", "And the three hundred and forty and ninth year had passed away."], ["Ma i le tausaga e tolu selau ma le limasefulu, na matou osia ai se feagaiga ma sa Lamanā ma le aufaomea a Katianetona,", "And in the three hundred and fiftieth year we made a treaty with the Lamanites and the robbers of Gadianton,"], ["lea na matou vaevaeina ai laueleele o o matou tofi.", "in which we did get the lands of our inheritance divided."]]},
  {num:29,words:[["Ma sa tuu mai e sa Lamanā ia te i matou le laueleele i matu,", "And the Lamanites did give unto us the land northward,"], ["ioe,", "yea,"], ["e oo atu lava i le ala lauitiiti lea e tau atu i le laueleele i saute. Ma sa matou tuu atu ia sa Lamanā le laueleele atoa i saute.", "even to the narrow passage which led into the land southward. And we did give unto the Lamanites all the land southward."]]},
];
renderVerseSet(mm_ch_2_Verses, 'mm-ch2-verses');

var mm_ch_3_Verses = [
  {num:1,words:[["Ma sa oo ina le toe o mai sa Lamanā e tau seia mavae le isi sefulu o tausaga. Ma faauta,", "And it came to pass that the Lamanites did not come to battle again until ten years more had passed away. And behold,"], ["sa ou faagalulueina ou tagata,", "I had employed my people,"], ["o sa Nifaē,", "the Nephites,"], ["i le sauniuniga o o latou laueleele ma a latou auupega tau mo le taimi o le taua.", "in preparing their lands and their arms against the time of battle."]]},
  {num:2,words:[["Ma sa oo ina fetalai mai le Alii ia te au:", "And it came to pass that the Lord did say unto me:"], ["Alaga atu i lenei nuu—Ia outou salamo,", "Cry unto this people—Repent ye,"], ["ma o mai ia te au,", "and come unto me,"], ["ma papatiso,", "and be ye baptized,"], ["ma toe atiae lau ekalesia,", "and build up again my church,"], ["ona faasaoina lea o outou.", "and ye shall be spared."]]},
  {num:3,words:[["Ma sa ou alaga i lenei nuu,", "And I did cry unto this people,"], ["ae sa le aoga;", "but it was in vain;"], ["ma sa latou le iloa o le Alii na faasaoina i latou,", "and they did not realize that it was the Lord that had spared them,"], ["ma tuu mai ia te i latou se avanoa e salamo ai. Ma faauta sa latou faamaaa o latou loto e faasaga i le Alii lo latou Atua.", "and granted unto them a chance for repentance. And behold they did harden their hearts against the Lord their God."]]},
  {num:4,words:[["Ma sa oo ina ua mavae atu le sefulu lea o tausaga,", "And it came to pass that after this tenth year had passed away, making,"], ["ma ua atoa ai le tolu selau ma le onosefulu o tausaga talu le afio mai o Keriso,", "in the whole,"], ["sa auina mai e le tupu o sa Lamanā se tusi ia te au,", "three hundred and sixty years from the coming of Christ,"], ["lea sa faailoa mai ai ia te au o loo latou sauniuni e toe o mai e faasaga tau mai ia te i matou.", "the king of the Lamanites sent an epistle unto me, which gave unto me to know that they were preparing to come again to battle against us."]]},
  {num:5,words:[["Ma sa oo ina ou faatonu atu i lou nuu ia latou potopoto faatasi i latou lava i le laueleele o Tuufua,", "And it came to pass that I did cause my people that they should gather themselves together at the land Desolation,"], ["i se aai sa i tuaoi,", "to a city which was in the borders,"], ["tafatafa ane o le ala lauitiiti lea sa tau atu i le laueleele i saute.", "by the narrow pass which led into the land southward."]]},
  {num:6,words:[["Ma o iina na matou tuu ai a matou autau,", "And there we did place our armies,"], ["ina ia mafai ona matou taofia o autau a sa Lamanā,", "that we might stop the armies of the Lamanites,"], ["ina ia le mafai ona latou maua o se tasi o o matou laueleele;", "that they might not get possession of any of our lands;"], ["o lea na matou ati ai olo faatasi ma a matou au uma e tetee ia te i latou.", "therefore we did fortify against them with all our force."]]},
  {num:7,words:[["Ma sa oo i le tausaga e tolu selau onosefulu ma le tasi,", "And it came to pass that in the three hundred and sixty and first year the Lamanites did come down to the city of Desolation to battle against us;"], ["sa oo ina o mai sa Lamanā i le aai o Tuufua e faasagatau mai ia te i matou; ma sa oo ina matou faatoilaloina i latou i le tausaga lena,", "and it came to pass that in that year we did beat them,"], ["sa oo ina latou toe foi atu i o latou lava laueleele.", "insomuch that they did return to their own lands again."]]},
  {num:8,words:[["Ma i le tausaga e tolu selau onosefulu ma le lua, sa latou toe o mai i lalo e tau.", "And in the three hundred and sixty and second year they did come down again to battle."], ["Ma sa matou toe faatoilaloina i latou,", "And we did beat them again,"], ["ma fasiotia se aofaiga tele o i latou,", "and did slay a great number of them,"], ["ma sa lafo o latou tagata oti i le sami.", "and their dead were cast into the sea."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["ona o lenei mea tele na faia e lou nuu,", "because of this great thing which my people,"], ["o sa Nifaē,", "the Nephites, had done,"], ["sa amata ona latou mitamita i lo latou lava malosi,", "they began to boast in their own strength,"], ["ma amata ona latou tauto i luma o le lagi o le a latou tauia le toto o o latou uso o e na fasiotia e o latou fili.", "and began to swear before the heavens that they would avenge themselves of the blood of their brethren who had been slain by their enemies."]]},
  {num:10,words:[["Ma sa latou tauto i le lagi,", "And they did swear by the heavens,"], ["ma i le nofoalii foi o le Atua,", "and also by the throne of God,"], ["o le a latou o ae e tau faasaga i o latou fili,", "that they would go up to battle against their enemies,"], ["ma sala ese i latou mai luga o le laueleele.", "and would cut them off from the face of the land."]]},
  {num:11,words:[["Ma o au,", "And it came to pass that I,"], ["o Mamona,", "Mormon,"], ["sa ou musu atoa mai i lena taimi e oo mai i luma e avea ma taitaiau ma se taitai o lenei nuu,", "did utterly refuse from this time forth to be a commander and a leader of this people,"], ["ona o lo latou amioleaga ma a latou mea inosia.", "because of their wickedness and abomination."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["e ui i lo latou amioleaga,", "I had led them,"], ["sa ou taitaiina i latou,", "notwithstanding their wickedness I had led them many times to battle,"], ["sa ou taitaia i latou i le tele o taimi i le taua,", "and had loved them,"], ["ma sa ou alofa ia te i latou, e tusa ma le alofa o le Atua sa ia te au,", "according to the love of God which was in me,"], ["ma lou loto atoa;", "with all my heart;"], ["ma sa sasaa atu lou agaga i le tatalo i le Atua i le aso atoa mo i latou;", "and my soul had been poured out in prayer unto my God all the day long for them;"], ["e ui i lea,", "nevertheless,"], ["sa faia e aunoa ma se faatuatua,", "it was without faith,"], ["ona o le maaa o o latou loto.", "because of the hardness of their hearts."]]},
  {num:13,words:[["Ma e faatolu ona ou laveaiina i latou mai lima o o latou fili,", "And thrice have I delivered them out of the hands of their enemies,"], ["ma ua latou le salamo lava mai ia latou agasala.", "and they have repented not of their sins."]]},
  {num:14,words:[["Ma ina ua latou tauto i mea uma na faasaina ai i latou e lo tatou Alii ma le Faaola o Iesu Keriso, o le a latou o ae i o latou fili e tau,", "And when they had sworn by all that had been forbidden them by our Lord and Savior Jesus Christ,"], ["ma latou taui le toto o o latou uso,", "that they would go up unto their enemies to battle,"], ["faauta,", "and avenge themselves of the blood of their brethren,"], ["sa oo mai le siufofoga o le Alii ia te au, ua fetalai mai:", "behold the voice of the Lord came unto me saying:"]]},
  {num:15,words:[["O le tauimasui e a au ia,", "Vengeance is mine,"], ["ma o le a ou toe totogi atu;", "and I will repay;"], ["ma ona ua le salamo lenei nuu ina ua uma ona ou laveaiina i latou,", "and because this people repented not after I had delivered them,"], ["faauta,", "behold,"], ["o le a vavae ese i latou mai luga o le lalolagi.", "they shall be cut off from the face of the earth."]]},
  {num:16,words:[["Ma sa oo ina ou musu atoatoa ou te alu ae e faasaga i ou fili;", "And it came to pass that I utterly refused to go up against mine enemies;"], ["ma sa ou faia lava e pei ona poloaiina ai au e le Alii;", "and I did even as the Lord had commanded me;"], ["ma sa ou tu o se molimau tu ese e faaali atu i le lalolagi mea sa ou vaaia ma faalogoina,", "and I did stand as an idle witness to manifest unto the world the things which I saw and heard,"], ["e tusa ma faaaliga a le Agaga ia na molimau mai e uiga i mea o le a oo mai.", "according to the manifestations of the Spirit which had testified of things to come."]]},
  {num:17,words:[["O lea ou te tusi atu ai ia te outou,", "Therefore I write unto you,"], ["o Nuuese,", "Gentiles,"], ["ma ia te outou foi,", "and also unto you,"], ["le aiga o Isaraelu,", "house of Israel,"], ["pe a amataina le galuega,", "when the work shall commence,"], ["o le a lata ona sauniunia o outou e toe foi atu i le laueleele o lo outou tofi;", "that ye shall be about to prepare to return to the land of your inheritance;"]]},
  {num:18,words:[["Ioe,", "Yea,"], ["faauta,", "behold,"], ["ou te tusi atu i tuluiga uma o le fogaelele;", "I write unto all the ends of the earth; yea,"], ["ioe,", "unto you,"], ["ia te outou ituaiga e sefululua o Isaraelu,", "twelve tribes of Israel,"], ["o e o le a faamasinoina e tusa ma a outou galuega e le toasefululua o e na filifilia e Iesu e avea mo ona soo i le laueleele o Ierusalema.", "who shall be judged according to your works by the  twelve whom Jesus chose to be his disciples in the land of Jerusalem."]]},
  {num:19,words:[["Ma ou te tusi atu foi i le toe vaega o lenei nuu,", "And I write also unto the remnant of this people,"], ["o e o le a faamasinoina foi e le toasefululua o e na filifilia e Iesu i lenei laueleele;", "who shall also be judged by the twelve whom Jesus chose in this land;"], ["ma o le a faamasinoina i latou e le isi toasefululua o e na filifilia e Iesu i le laueleele o Ierusalema.", "and they shall be judged by the other twelve whom Jesus chose in the land of Jerusalem."]]},
  {num:20,words:[["Ma o nei mea na faaali mai e le Agaga ia te au;", "And these things doth the Spirit manifest unto me;"], ["o lea ou te tusi atu ai ia te outou uma. Ma o le pogai lenei ua ou tusi atu ai ia te outou,", "therefore I write unto you all. And for this cause I write unto you,"], ["ina ia outou iloa o le a outou tutu uma i luma o le nofoa-faamasino o Keriso,", "that ye may know that ye must all stand before the judgment– seat of Christ,"], ["ioe,", "yea,"], ["o tagata uma taitoatasi o e ua i ai i le aiga tagata atoa o Atamu;", "every soul who belongs to the whole human family of Adam;"], ["ma o le a outou tutu e faamasinoina i a outou galuega,", "and ye must stand to be judged of your works,"], ["pe ua lelei pe ua leaga;", "whether they be good or evil;"]]},
  {num:21,words:[["Ma ina ia outou talitonu foi i le talalelei a Iesu Keriso,", "And also that ye may believe the gospel of Jesus Christ,"], ["lea o le a outou maua i totonu ia te outou;", "which ye shall have among you;"], ["ma ina ia maua foi e tagata Iutaia ,", "and also that the Jews,"], ["le nuu o le feagaiga a le Alii,", "the covenant people of the Lord,"], ["isi molimau e ese mai ia te ia o le na latou vaai ma faalogo i ai,", "shall have other witness besides him whom they saw and heard,"], ["o Iesu,", "that Jesus,"], ["o le na latou fasiotia,", "whom they slew,"], ["o le Keriso moni ma le Atua moni lava lea.", "was the very Christ and the very God."]]},
  {num:22,words:[["Ma ou te moomoo maumau pe a na mafai ona ou faatauanauina outou uma tuluiga o le lalolagi ia outou salamo ma sauni e tutu i luma o le nofoa-faamasino o Keriso.", "And I would that I could persuade all ye ends of the earth to repent and prepare to stand before the judgment–seat of Christ."]]},
];
renderVerseSet(mm_ch_3_Verses, 'mm-ch3-verses');

var mm_ch_4_Verses = [
  {num:1,words:[["Ma o lenei, sa oo i le tausaga e tolu selau onosefulu ma le tolu,", "And now it came to pass that in the three hundred and sixty and third year the Nephites did go up with their armies to battle against the Lamanites,"], ["na o ae sa Nifaē ma a latou autau e faasaga tau ia sa Lamanā, i fafo mai le laueleele o Tuufua.", "out of the land Desolation."]]},
  {num:2,words:[["Ma sa oo ina toe tulia mai i tua autau a sa Nifaē i le laueleele o Tuufua. Ma ao latou vaivai,", "And it came to pass that the armies of the Nephites were driven back again to the land of Desolation. And while they were yet weary,"], ["sa o mai se autau fou a sa Lamanā i luga o i latou;", "a fresh army of the Lamanites did come upon them;"], ["ma sa latou faia se taua malosi tele,", "and they had a sore battle,"], ["sa oo ina maua e sa Lamana le aai o Tuufua,", "insomuch that the Lamanites did take possession of the city Desolation,"], ["ma fasiotia le toatele o sa Nifaē,", "and did slay many of the Nephites,"], ["ma ave faapagota le toatele.", "and did take many prisoners."]]},
  {num:3,words:[["Ma o e na totoe na sosola ma ua aufaatasi ma tagata o le aai o Teanekuma. O lenei o le aai o Teanekuma sa faalava i tuaoi i tafatafa o le matafaga,", "And the remainder did flee and join the inhabitants of the city Teancum. Now the city Teancum lay in the borders by these ashore;"], ["ma sa latalata foi i le aai o Tuufua.", "and it was also near the city Desolation."]]},
  {num:4,words:[["Ma sa amata ona taiaina o i latou,", "And it was because the armies of the Nephites went up unto the Lamanites that they began to be smitten;"], ["ona ua o ae fua o autau a sa Nifaē ia sa Lamanā; aua a na leai lena mea,", "for were it not for that,"], ["semanu e leai se mana o sa Lamana i luga o i latou.", "the Lamanites could have had no power over them."]]},
  {num:5,words:[["Ae,", "But,"], ["faauta,", "behold,"], ["e maua e faamasinoga a le Atua e e amioleaga;", "the judgments of God will overtake the wicked;"], ["ma o e amioleaga e faasalaina e e amioleaga;", "and it is by the wicked that the wicked are punished;"], ["ona o e e amioleaga latou te faaosoina loto o le fanauga a tagata i le faamasaa toto.", "for it is the wicked that stir up the hearts of the children of men unto bloodshed."]]},
  {num:6,words:[["Ma sa oo ina faia e sa Lamanā sauniuniga e o mai e faasaga i le aai o Teanekuma.", "And it came to pass that the Lamanites did make preparations to come against the city Teancum."]]},
  {num:7,words:[["Ma sa oo i le tausaga e tolu selau onosefulu ma le fa na o mai ai sa Lamanā e faasaga i le aai o Teanekuma,", "And it came to pass in the three hundred and sixty and fourth year the Lamanites did come against the city Teancum,"], ["ina ia mafai ona latou ave foi o le aai o Teanekuma.", "that they might take possession of the city Teancum also."]]},
  {num:8,words:[["Ma sa oo ina teena ma toe tulia i tua i latou e sa Nifaē.", "And it came to pass that they were repulsed and driven back by the Nephites."], ["Ma ina ua vaai sa Nifaē ua latou tutulia sa Lamanā,", "And when the Nephites saw that they had driven the Lamanites they did again boast of their own strength;"], ["sa latou toe mitamita i lo latou lava malosi; ma sa latou o atu i lo latou lava malosi,", "and they went forth in their own might,"], ["ma toe ave le aai o Tuufua.", "and took possession again of the city Desolation."]]},
  {num:9,words:[["Ma o lenei o nei mea uma sa faia,", "And now all these things had been done,"], ["ma sa tele afe na fasiotia ai i itu uma e lua,", "and there had been thousands slain on both sides,"], ["o sa Nifaē ma sa Lamanā.", "both the Nephites and the Lamanites."]]},
  {num:10,words:[["Ma sa oo ina mavae atu le tausaga e tolu selau onosefulu ma le ono,", "And it came to pass that the three hundred and sixty and sixth year had passed away,"], ["ma sa toe o mai foi sa Lamanā i luga o sa Nifaē e tau;", "and the Lamanites came again upon the Nephites to battle;"], ["ma sa le salamo lava sa Nifaē i le leaga na latou faia,", "and yet the Nephites repented not of the evil they had done,"], ["ae mauai pea i lo latou amioleaga e le aunoa.", "but persisted in their wickedness continually."]]},
  {num:11,words:[["Ma e le mafai e le laulaufaiva ona faamatalaina,", "And it is impossible for the tongue to describe,"], ["pe mafai foi e le tagata ona tusi se faamatalaga atoatoa o le vaaiga matautia o le toto ma tagata fasiotia sa i ai i totonu o tagata,", "or for man to write a perfect description of the horrible scene of the blood and carnage which was among the people,"], ["o sa Nifaē ma sa Lamanā;", "both of the Nephites and of the Lamanites;"], ["ma sa faamaaa loto uma,", "and every heart was hardened,"], ["sa oo ina latou fiafia i le faamasaaina o le toto e le aunoa.", "so that they delighted in the shedding of blood continually."]]},
  {num:12,words:[["Ma sa leai se amioleaga tele faapea sa i ai i totonu o le fanau uma a Liae,", "And there never had been so great wickedness among all the children of Lehi,"], ["po o totonu o le aiga uma o Isaraelu,", "nor even among all the house of Israel,"], ["e tusa ai ma fetalaiga a le Alii,", "according to the words of the Lord,"], ["e pei ona i ai i totonu o lenei nuu.", "as was among this people."]]},
  {num:13,words:[["Ma sa oo ina maua e sa Lamanā le aai o Tuufua,", "And it came to pass that the Lamanites did take possession of the city Desolation,"], ["ma o le pogai ona sa sili atu le tele lo latou aofai nai lo le aofai o sa Nifaē.", "and this because their number did exceed the number of the Nephites."]]},
  {num:14,words:[["Ma sa latou savavali atu foi i luma e faasaga i le aai o Teanekuma,", "And they did also march forward against the city Teancum,"], ["ma latou tutuli ese i fafo tagata mai ia te ia,", "and did drive the inhabitants forth out of her,"], ["ma latou ave faapagota le toatele, o fafine ma tamaiti,", "and did take many prisoners both women and children,"], ["ma latou tuu atu i latou o ni taulaga i o latou atua tupua.", "and did offer them up as sacrifices unto their idol gods."]]},
  {num:15,words:[["Ma sa oo i le tausaga e tolu selau onosefulu ma le fitu,", "And it came to pass that in the three hundred and sixty and seventh year,"], ["i le feita o sa Nifaē ona ua osi e sa Lamanā taulaga i o latou fafine ma o latou tamaiti,", "the Nephites being angry because the Lamanites had sacrificed their women and their children,"], ["sa oo ina latou o atu e faasaga ia sa Lamanā ma le ita tele,", "that they did go against the Lamanites with exceedingly great anger,"], ["sa oo ina latou toe faatoilaloina sa Lamanā,", "insomuch that they did beat again the Lamanites,"], ["ma ua tuli esea i latou i fafo mai i o latou laueleele.", "and drive them out of their lands."]]},
  {num:16,words:[["Ma sa le toe o mai sa Lamanā e faasaga mai ia sa Nifaē seia oo i le tausaga e tolu selau fitusefulu ma le lima.", "And the Lamanites did not come again against the Nephites until the three hundred and seventy and fifth year."]]},
  {num:17,words:[["Ma i le tausaga lenei, sa latou o mai i lalo e faasaga mai ia sa Nifaē ma lo latou malosi uma;", "And in this year they did come down against the Nephites with all their powers;"], ["ma sa le faitaulia i latou ona o le toatele naua o lo latou aofai.", "and they were not numbered because of the greatness of their number."]]},
  {num:18,words:[["Ma sa amata mai i lenei taimi i luma ona le toe maua e sa Nifaē se mana i luga o sa Lamanā,", "And from this time forth did the Nephites gain no power over the Lamanites,"], ["ae sa amata ona tafi ese o i latou e i latou e pei o le sau i luma o le la.", "but began to be swept off by them even as a dew before the sun."]]},
  {num:19,words:[["Ma sa oo ina o mai sa Lamanā i lalo e faasaga i le aai o Tuufua;", "And it came to pass that the Lamanites did come down against the city Desolation;"], ["ma sa i ai se taua tiga tele na tauina i le laueleele o Tuufua,", "and there was an exceedingly sore battle fought in the land Desolation,"], ["lea na latou faatoilalo ai sa Nifaē.", "in the which they did beat the Nephites."]]},
  {num:20,words:[["Ma sa latou toe sosola mai i o latou luma,", "And they fled again from before them,"], ["ma latou o mai ai i le aai o Poasa;", "and they came to the city Boaz;"], ["ma o iina na latou tu tetee atu ai ia sa Lamanā ma le totoa tele,", "and there they did stand against the Lamanites with exceeding boldness,"], ["sa oo ina le faatoilaloina i latou e sa Lamanā seia oo ina latou toe o mai i le taimi lona lua.", "insomuch that the Lamanites did not beat them until they had come again the second time."]]},
  {num:21,words:[["Ma ina ua latou toe o mai i le taimi lona lua,", "And when they had come the second time,"], ["sa tutulia ma fasia sa Nifaē i se fasiga tele lava;", "the Nephites were driven and slaughtered with an exceedingly great slaughter;"], ["sa toe taulagaina o latou fafine ma o latou tamaiti i tupua.", "their women and their children were again sacrificed unto idols."]]},
  {num:22,words:[["Ma sa oo ina toe sosola sa Nifaē mai i o latou luma,", "And it came to pass that the Nephites did again flee from before them,"], ["ma ave faatasi ma i latou tagata uma,", "taking all the inhabitants with them,"], ["sa i faoa aai ma nuu.", "both in town sand villages."]]},
  {num:23,words:[["Ma o lenei,", "And now I,"], ["o au,", "Mormon,"], ["o Mamona, ina ua ou vaai o le a faatoilalo e sa Lamanā le laueleele,", "seeing that the Lamanites were about to overthrow the land,"], ["o lea na ou alu atu ai i le mauga o Semi ,", "therefore I did go to the hill Shim,"], ["ma ou ave talafaamaumau uma ia na natia mau e Amorona mo le Alii.", "and did take up all the records which Ammaron had hid up unto the Lord."]]},
];
renderVerseSet(mm_ch_4_Verses, 'mm-ch4-verses');

var mm_ch_5_Verses = [
  {num:1,words:[["Ma sa oo ina ou alu atu i totonu o tagata sa Nifaē,", "And it came to pass that I did go forth among the Nephites,"], ["ma sa ou salamo i le tautoga na ou faia ou te le toe fesoasoani ia te i latou;", "and did repent of the oath which I had made that I would no more assist them;"], ["ma sa latou toe tuu mai ia te au le pulega o a latou autau,", "and they gave me command again of their armies,"], ["ona sa latou vaai mai ia te au e peiseai e mafai ona laveaiina i latou mai i o latou puapuaga.", "for they looked upon me as though I could deliver them from their afflictions."]]},
  {num:2,words:[["Ae faauta,", "But behold,"], ["sa aunoa au ma se faamoemoe,", "I was without hope,"], ["aua sa ou iloa faamasinoga ia a le Alii o le a oo mai i luga ia te i latou;", "for I knew the judgments of the Lord which should come upon them;"], ["ona sa latou le salamo ia latou amioletonu,", "for they repented not of their iniquities,"], ["ae sa latou tau mo o latou ola e aunoa ma le valaau atu i le Atua lena o le na faia i latou.", "but did struggle for their lives without calling upon that Being who created them."]]},
  {num:3,words:[["Ma sa oo ina o mai sa Lamanā e faasaga mai ia te i matou ina ua matou sosola atu i le aai o Ioritana;", "And it came to pass that the Lamanites did come against us as we had fled to the city of Jordan;"], ["ae faauta,", "but behold,"], ["sa tutulia i latou i tua sa latou le avea ai le aai i le taimi lena.", "they were driven back that they did not take the city at that time."]]},
  {num:4,words:[["Ma sa oo ina latou toe o mai e faasaga mai ia te i matou,", "And it came to pass that they came against us again,"], ["ma sa matou taofia le aai.", "and we did maintain the city."], ["Ma sa i ai foi isi aai sa taofi e sa Nifaē,", "And there were also other cities which were maintained by Nephites,"], ["o liumalolosi ia na sisio mai ai i latou, sa le mafai ai ona latou o atu i le laufanua lea sa i o matou luma,", "which strongholds did cut them off that they could not get into the country which lay before us,"], ["e faaumatia tagata o lo matou laueleele.", "to destroy the inhabitants of our land."]]},
  {num:5,words:[["Ae sa oo ina o soo se laueleele na matou ui atu ai,", "And it came to pass that whatsoever lands we had passed by,"], ["ma sa lei faapotopotoina faatasi o latou tagata,", "and the inhabitants thereof were not gathered in,"], ["sa faaumatia e sa Lamanā,", "were destroyed by the Lamanites,"], ["ma o o latou faoa aai,", "and their towns,"], ["ma nuu,", "and villages,"], ["ma aai sa susunu i le afi;", "and cities were burned with fire;"], ["ma sa faapea ona mavae atu o le tolu selau fitusefulu ma le iva o tausaga.", "and thus three hundred and seventy and nine years passed away."]]},
  {num:6,words:[["Ma sa oo i le tausaga e tolu selau ma le valusefulu,", "And it came to pass that in the three hundred and eightieth year the Lamanites did come again against us to battle,"], ["sa toe o mai ai sa Lamanā e faasagatau mai ia te i matou,", "and we did stand against them boldly;"], ["ma sa matou tutu tetee atu i te i latou ma le totoa; peitai sa le aoga uma,", "but it was all in vain,"], ["ona sa matua toatele lava lo latou aofai sa oo ina latou soli i lalo o o latou vae tagata sa Nifaē.", "for so great were their numbers that they did tread the people of the Nephites under their feet."]]},
  {num:7,words:[["Ma sa oo ina matou toe sosola,", "And it came to pass that we did again take to flight,"], ["ma o i latou o e na televavave atu la latou solaaga nai lo sa Lamanā sa sosola ese,", "and those whose flight was swifter than the Lamanites’ did escape,"], ["ae o i latou o e sa le televavave atu la latou solaaga nai lo sa Lamana sa tafi i lalo ma faaumatiaina.", "and those whose  flight did not exceed the Lamanites’ were swept down and destroyed."]]},
  {num:8,words:[["Ma o lenei faauta,", "And now behold,"], ["o au,", "I,"], ["o Mamona,", "Mormon,"], ["ou te le manao e laga i luga agaga o tagata i le tuuina atu i o latou luma o se vaaiga matautia o le toto ma le tele o tagata oti e pei ona folasia i luma o ou mata;", "do not desire to harrow up the souls of men in casting before them such an awful scene of blood and carnage as was laid before mine eyes;"], ["ae o au,", "but I,"], ["i lou iloa o nei mea e ao moni lava ona faaalia,", "knowing that these things must surely be made known,"], ["ma o mea uma ua natia o le a faaalia lava i luga o tumutumu o fale—", "and that all things which are hid must be revealed upon the house– tops—"]]},
  {num:9,words:[["Ma e ao foi ona oo atu se malamalama e uiga i nei mea i le toe vaega o nei tagata,", "And also that a knowledge of these things must come unto the remnant of these people,"], ["ma i Nuuese foi,", "and also unto the Gentiles,"], ["o e na fetalai mai le Alii o le a faataapeapeina lenei nuu,", "who the Lord hath said should scatter this people,"], ["ma o le a faitauina nei tagata o ni meanoa i totonu o i latou—o lea ou te tusia ai se otootoga laitiiti,", "and this people should be counted as naught among them—therefore I write a small abridgment,"], ["ma ou le sopo e tuuina atu se tala atoa o mea na ou vaaia,", "daring not to give a full account of the things which I have seen,"], ["ona o le poloaiga lea na ou mauaina,", "because of the commandment which I have received,"], ["ma ina ia le oo foi ia te outou le faanoanoa tele ona o le amioleaga o lenei nuu.", "and also that ye might not have too great sorrow because of the wickedness of this people."]]},
  {num:10,words:[["Ma o lenei faauta,", "And now behold,"], ["o le mea lenei ou te tautala atu ia latou fanau,", "this I speak unto their seed,"], ["ma Nuuese foi o e o le a i ai le tausiga o le aiga o Isaraelu,", "and also to the Gentiles who have care for the house of Israel,"], ["o e e malamalama ma iloa le mea e sau ai o latou faamanuiaga.", "that realize and know from whence their blessings come."]]},
  {num:11,words:[["Aua ua ou iloa o tagata faapena o le a faanoanoa i le malaia o le aiga o Isaraelu;", "For I know that such will sorrow for the calamity of the house of Israel;"], ["ioe,", "yea,"], ["o le a latou faanoanoa mo le faaumatiaga o lenei nuu;", "they will sorrow for the destruction of this people;"], ["o le a latou faanoanoa ona sa le salamo lenei nuu semanu po ua mafai ai ona opoina i latou i aao o Iesu.", "they will sorrow that this people had not repented that they might have been clasped in the arms of Jesus."]]},
  {num:12,words:[["O lenei ua tusia nei mea i le toe vaega o le aiga o Iakopo;", "Now these things are written unto the remnant of the house of Jacob;"], ["ma ua tusia nei mea i lenei ala,", "and they are written after this manner,"], ["ona ua silafia e le Atua o le a le aumaia i latou ia te i latou;", "because it is known of God that wickedness will not bring them forth unto them;"], ["ae ia natia mau i latou mo le Alii ina ia oo mai i latou i lana lava taimi e tatau ai.", "and they are to be hid up unto the Lord that they may come forth in his own due time."]]},
  {num:13,words:[["Ma o le poloaiga lenei na ou mauaina;", "And this is the commandment which I have received;"], ["faauta foi,", "and behold,"], ["o le a oo mai ia mea e tusa ma le poloaiga a le Alii,", "they shall come forth according to the commandment of the Lord,"], ["pe a silafia e ia i lona poto,", "when he shall see fit,"], ["ua tatau ai.", "in his wisdom."]]},
  {num:14,words:[["Faauta foi,", "And behold,"], ["o le a oo atu nei mea i e e le talitonu o tagata Iutaia ;", "they shall go unto the unbelieving of the Jews;"], ["ma o le faamoemoe lenei o le a latou o atu ai—ina ia mafai ona faatauanauina ai i latou o Iesu o le Keriso,", "and for this intent shall they go—that they may be persuaded that Jesus is the Christ,"], ["o le Alo o le Atua soifua;", "the Son of the living God;"], ["ina ia mafai ona faataunuuina e le Tamā,", "that the Father may bring about,"], ["e ala i lana Pele sili,", "through his most Beloved,"], ["lana fuafuaga sili ma faavavau,", "his great and eternal purpose,"], ["i le toefuataiina o tagata Iutaia,", "in restoring the Jews,"], ["po o le aiga uma o Isaraelu,", "or all the house of Israel,"], ["i le laueleele o lo latou tofi,", "to the land of their inheritance,"], ["lea na tuuina mai ia te i latou e le Alii lo latou Atua,", "which the Lord their God hath given them,"], ["mo le faataunuuina o lana feagaiga .", "unto the fulfilling of his covenant;"]]},
  {num:15,words:[["Ma ia mafai ai foi e fanau o lenei nuu ona talitonu atoatoa i lana talalelei,", "And also that the seed of this people may more fully believe his gospel,"], ["lea o le a alu atu ia te i latou mai Nuuese;", "which shall go forth unto them from the Gentiles;"], ["ona o le a faataapeapeina lenei nuu,", "for this people shall be scattered,"], ["ma o le a avea ma ni tagata faauliuli,", "and shall become a dark,"], ["eleelea,", "a filthy, and a loathsome people,"], ["ma inosia,", "beyond the description of that which ever hath been amongst us,"], ["e sili atu i le faamatalaga o mea sa i ai i totonu o i matou,", "yea,"], ["e oo lava i mea sa i ai i totonu o sa Lamanā;", "even that which hath been  among the Lamanites,"], ["ma o le pogai o lenei mea ona o lo latou le talitonu ma le ifo i tupua.", "and this because of their unbelief and idolatry."]]},
  {num:16,words:[["Aua faauta,", "For behold,"], ["ua uma ona le toe taumafai o le Agaga o le Alii i o latou tamā;", "the Spirit of the Lord hath already ceased to strive with their fathers;"], ["ma ua latou aunoa ma Keriso ma le Atua i le lalolagi;", "and they are without Christ and God in the world;"], ["ma ua fetulinai solo i latou e pei o aputi o saito i luma o le matagi.", "and they are driven about as chaff before the wind."]]},
  {num:17,words:[["Sa avea i latou muamua o ni tagata moomia,", "They were once a delightsome people,"], ["ma sa latou avea Keriso mo o latou leoleo mamoe;", "and they had Christ for their shepherd;"], ["ioe,", "yea,"], ["sa taitaiina lava i latou e le Atua le Tamā.", "they were led even by God the Father."]]},
  {num:18,words:[["Ae i le taimi nei,", "But now,"], ["faauta,", "behold,"], ["ua taitai solo i latou e Satani,", "they are led about by Satan,"], ["e pei o aputi o saito ua lelea i luma o le matagi,", "even as chaff is driven before the wind,"], ["pe pei o se vaa ua felafoaiina solo i luga o peau,", "or as a vessel is tossed about upon the waves,"], ["ua aunoa ma se la po o se taula,", "without sail or anchor,"], ["pe ua aunoa foi ma se mea e mafai ona uli ai o ia;", "or without anything where with to steer her;"], ["ma e pei lava ona i ai o ia,", "and even as she is,"], ["ua faapea lava i latou.", "so are they."]]},
  {num:19,words:[["Faauta foi,", "And behold,"], ["ua taofia e le Alii o latou faamanuiaga,", "the Lord hath reserved their blessings,"], ["ia semanu latou te maua i le laueleele,", "which they might have received in the land,"], ["mo Nuuese o e o le a mauaina le laueleele.", "for the Gentiles who shall possess the land."]]},
  {num:20,words:[["Ae faauta,", "But behold,"], ["o le a oo mai o le a tutulia ma faataapeapeina ai i latou e Nuuese;", "it shall come to pass that they shall be driven and scattered by the Gentiles;"], ["ma pe a uma ona tutulia ma faataapeapeina i latou e Nuuese,", "and after they have been driven and scattered by the Gentiles,"], ["faauta,", "behold,"], ["ona manatua ai lea e le Alii le feagaiga lea na ia faia ma Aperaamo ma le aiga uma o Isaraelu.", "then will the Lord remember the covenant which he made unto Abraham and unto all the house of Israel."]]},
  {num:21,words:[["Ma o le a manatua foi e le Alii tatalo a e amiotonu,", "And also the Lord will remember the prayers of the righteous,"], ["ia sa tuuina atu ia te ia mo i latou.", "which have been put up unto him for them."]]},
  {num:22,words:[["Ma o lea,", "And then,"], ["Outou Nuuese e,", "O ye Gentiles,"], ["e mafai faapefea ona outou tutu atu i luma o le mana o le Atua,", "how can ye stand before the power of God,"], ["vagana ai ua outou salamo ma liliu ese mai i o outou ala leaga?", "except ye shall repent and turn from your evil ways?"]]},
  {num:23,words:[["Tou te le iloa ea ua outou i ai i aao o le Atua? Tou te le iloa ea ua ia te ia le mana uma,", "Know ye not that ye are in the hands of God? Know ye not that he hath all power,"], ["ma o lana poloai silisili e taataai faatasi ai le lalolagi e pei o se tusitaai?", "and at his great command the earth shall be rolled together as a scroll?"]]},
  {num:24,words:[["O lea,", "Therefore,"], ["ia outou salamo,", "repent ye,"], ["ma faamaualalo outou lava i ona luma,", "and humble your selves before him,"], ["nei afio mai o ia i le faamasinotonu e faasaga ia te outou—nei o atu i totonu ia te outou se toe vaega o le fanau a Iakopo e pei o se leona ,", "lest he shall come out in justice against you—lest a remnant of the seed of Jacob shall go forth among you as a lion,"], ["ma saeia lilii outou,", "and tear you in pieces,"], ["ma e leai se e laveaiina.", "and there is none to deliver."]]},
];
renderVerseSet(mm_ch_5_Verses, 'mm-ch5-verses');

var mm_ch_6_Verses = [
  {num:1,words:[["Ma o lenei ou te faaiu lau talafaamaumau e faatatau i le faaumatiaga o ou tagata,", "And now I finish my record concerning the destruction of my people,"], ["o sa Nifaē. Ma sa oo ina matou savavali atu i luma o sa Lamanā.", "the Nephites. And it came to pass that we did march forth before the Lamanites."]]},
  {num:2,words:[["Ma o au,", "And I,"], ["o Mamona,", "Mormon,"], ["sa ou tusi atu se tusi i le tupu o sa Lamanā,", "wrote an epistle unto the king of the Lamanites,"], ["ma ou manao mai ia te ia ia ona tuu mai i matou ia matou faapotopoto faatasi o matou tagata i le laueleele o Kumora,", "and desired of him that he would grant unto us that we might gather together our people unto the land of Cumorah,"], ["i tafatafa o se maupuepue ua taua o Kumora,", "by a hill which was called Cumorah,"], ["ma o iina o le a matou tau ai ma i latou.", "and there we could give them battle."]]},
  {num:3,words:[["Ma sa oo ina tuu mai e le tupu o sa Lamanā ia te au le mea na ou manao ai.", "And it came to pass that the king of the Lamanites did grant unto me the thing which I desired."]]},
  {num:4,words:[["Ma sa oo ina matou savavali atu i le laueleele o Kumora,", "And it came to pass that we did march forth to the land of Cumorah,"], ["ma sa matou faatutu o matou faleie faataamilo i le mauga o Kumora;", "and we did pitch our tents around about the hill Cumorah;"], ["ma o se laueleele sa tele ai vai,", "and it was in a land of many waters,"], ["o vaitafe,", "rivers,"], ["ma vaipuna;", "and fountains;"], ["ma o iinei na matou faamoemoe o le a matou maua ai se lelei sili atu i luga o sa Lamanā.", "and  here we had hope to gain advantage over the Lamanites."]]},
  {num:5,words:[["Ma e mavae atu le toluselau valusefulu ma le fa o tausaga ua matou faapotopotoina faatasi o matou tagata uma na totoe i le laueleele o Kumora.", "And when three hundred and eighty and four years had passed away, we had gathered in all the remainder of our people unto the land of Cumorah."]]},
  {num:6,words:[["Ma sa oo ina ua uma ona matou faapotopoto faatasi o matou tagata uma i le laueleele o Kumora,", "And it came to pass that when we had gathered in all our people in one to the land of Cumorah,"], ["faauta,", "behold I,"], ["o au,", "Mormon,"], ["o Mamona,", "began to be old;"], ["sa amata ona ou toeaina;", "and knowing it to be the last struggle of my people,"], ["ma i lou iloa o le taua faaiu lea a lou nuu,", "and having been commanded of the Lord that I should not suffer the records which had been handed down by our fathers,"], ["ma ina ua poloaiina au e le Alii ia ou le tuuina talafaamaumau ia na tuulima faasolo mai i lalo e o matou tamā,", "which were sacred,"], ["ina ia pauu atu i lima o sa Lamanā,", "to fall into the hands of the Lamanites,"], ["(ona e faaumatia i latou e sa Lamanā) o lea na ou faia ai lenei talafaamaumau mai papatusi a Nifae,", "(for the Lamanites would destroy them) therefore I made this record out of the plates of Nephi,"], ["ma natia mau i le maupuepue o Kumora talafaamaumau uma na tuuina mai ia te au e le aao o le Alii,", "and hid up in the hill Cumorah all the records which had been entrusted to me by the hand of the Lord,"], ["vagana ai nai papatusi itiiti nei na ou tuuina atu i lou atalii o Moronae .", "save it were these few plates which I gave unto my son Moroni."]]},
  {num:7,words:[["Ma sa oo ina iloa atu nei e ou tagata,", "And it came to pass that my people,"], ["ma a latou ava ma a latou fanau,", "with their wives and their children,"], ["autau a sa Lamanā ua savavali agai mai ia te i latou;", "did now behold the armies of the Lamanites marching towards them;"], ["ma ua latou faatalitalia i latou,", "and with that awful fear of death which fills the breasts of all the wicked,"], ["faatasi ma lena mata'u tele i le oti e faatumulia ai loto o i latou uma o e e amioleaga.", "did they await to receive them."]]},
  {num:8,words:[["Ma sa oo ina latou o mai e faasagatau mai ia te i matou,", "And it came to pass that they came to battle against us,"], ["ma sa faatumuina tagata taitoatasi i le matau ona o le toatele naua o lo latou aofai.", "and every soul was filled with terror because of the greatness of their numbers."]]},
  {num:9,words:[["Ma sa oo ina latou pauu mai i luga o lou nuu ma le pelu,", "And it came to pass that they did fall upon my people with the sword,"], ["ma le aufana,", "and with the bow,"], ["ma le ufanafana,", "and with the arrow,"], ["ma le matau,", "and with the ax,"], ["ma auupega uiga eseese uma o taua.", "and with all manner of weapons of war."]]},
  {num:10,words:[["Ma sa oo ina salaina i lalo au tagata,", "And it came to pass that my men were hewn down,"], ["ioe,", "yea,"], ["lau sefulu afe lava o e sa faatasi ma au,", "even my ten thousand who were with me,"], ["ma sa ou pau ua manua i totonu o i latou;", "and I fell wounded in the midst;"], ["ma sa latou pasi ane ia te au ma sa latou le faaumaina ai lou ola.", "and they passed by me that they did not put an end to my life."]]},
  {num:11,words:[["Ma ina ua uma ona latou ala atu ma sala i lalo ou tagata uma vagana ai le luasefulu ma le fa o i matou,", "And when they had gone through and hewn down all my people save it were twenty and four of us,"], ["(na aofia ai i totonu lou atalii o Moronae) ma ua faaolatia mai i matou i e na oti o lo matou nuu,", "(among whom was my son Moroni) and we having survived the dead of our people,"], ["sa matou vaaia i le aso na sosoo ai,", "did behold on the morrow,"], ["mai luga o le maupuepue o Kumora,", "when the Lamanites had returned unto their camps,"], ["ina ua toe foi atu sa Lamanā i o latou togalauapiga,", "from the top of the hill Cumorah,"], ["le sefulu afe o ou tagata o e na sala i lalo,", "the ten thousand of my people who were hewn down,"], ["o e na ou taitaia i luma.", "being led in the front by me."]]},
  {num:12,words:[["Ma sa matou vaaia foi le sefulu afe o ou tagata o e sa taitaia e lou atalii o Moronae.", "And we also beheld the ten thousand of my people who were led by my son Moroni."]]},
  {num:13,words:[["Faauta foi,", "And behold,"], ["sa pauu foi le sefulu afe a Kitakitona,", "the ten thousand of Gid– giddonah had fallen,"], ["ma ia foi i totonu o i latou.", "and he also in the midst."]]},
  {num:14,words:[["Ma sa pau foi Lama ma faatasi ma lana sefulu afe;", "And Lamah had fallen with his ten thousand;"], ["ma sa pau foi Kilikala faatasi ma lana sefulu afe;", "and Gilgal had fallen with his ten thousand;"], ["ma sa pau foi Lima ma lana sefulu afe;", "and Limhah had fallen with his ten thousand;"], ["ma sa pau foi Ioneama ma lana sefulu afe;", "and Jeneum had fallen with his ten thousand;"], ["ma sa pauu foi Kamenaea,", "and Cumenihah, and Moronihah,"], ["ma Moronaea,", "and Antionum,"], ["ma Anetionuma,", "and Shiblom,"], ["ma Sepeloma,", "and Shem,"], ["ma Semu,", "and Josh,"], ["ma Iosa faatasi ma a latou tai sefulu afe.", "had fallen with their ten thousand each."]]},
  {num:15,words:[["Ma sa oo ina sa i ai foi le isi toasefulu faaopoopo o e na pauu foi i le pelu faatasi ma a latou tai sefulu afe;", "And it came to pass that there were ten more who did fall by the sword,"], ["ioe,", "with their ten thousand each;"], ["o ou tagata uma lava,", "yea,"], ["vagana ai i latou ia e luasefulu ma le fa o e na faatasi ma au,", "even all my people,"], ["ma ni isi foi e toaitiiti o e na sosola i laueleele i saute,", "save it were those twenty and four who were with me,"], ["ma se toaitiiti o e na sosola atu ma ua aufaatasi ma sa Lamanā,", "and also a few who had escaped into the south countries,"], ["ua pauu;", "and a few who had deserted over unto the Lamanites,"], ["ma ua taatitia o latou tino,", "had fallen;"], ["ma ivi,", "and their flesh,"], ["ma toto,", "and bones,"], ["i luga o le lalolagi,", "and blood lay upon the face of the earth,"], ["ua tuu e lima o e na fasia i latou ia pala i luga o le laueleele,", "being left by the hands of those who slew them to molder upon the land,"], ["ma ia nuti ma toe foi i lo latou tinā o le eleele.", "and to crumble and to return to their mother earth."]]},
  {num:16,words:[["Ma sa saeia lou agaga i le mafatia,", "And my soul was rent with anguish,"], ["ona o e o lou nuu ua fasia,", "because of the slain of my people,"], ["ma sa ou tagi ae:", "and I cried:"]]},
  {num:17,words:[["E, outou tagata lalelei e,", "O ye fair ones,"], ["pe na mafai faapefea ea ona outou o ese mai ala o le Alii! E,", "how could ye have departed from the ways of the Lord! O ye fair ones,"], ["outou tagata lalelei e,", "how could ye have rejected that Jesus,"], ["pe na mafai faapefea ea ona outou teena Iesu lena, o le na tu mai ma aao faaloaloa mai e tali outou!", "who stood with open arms to receive you!"]]},
  {num:18,words:[["Faauta,", "Behold,"], ["a na outou le faia lenei mea,", "if ye had not done this,"], ["po ua outou le pauu. Ae faauta,", "ye would not have fallen. But behold,"], ["ua outou pauu,", "ye are fallen,"], ["ma ua ou faanoanoa i le toesea o outou.", "and I mourn your loss."]]},
  {num:19,words:[["E,", "O ye fair sons and daughters,"], ["outou atalii ma afafine lalelei e,", "ye fathers and mothers,"], ["outou tamā ma tinā, outou tane ma ava,", "ye husbands and wives,"], ["outou tagata lalelei e,", "ye fair ones,"], ["ua mafai faapefea ea ona outou pauu!", "how is it that ye could have fallen!"]]},
  {num:20,words:[["Ae faauta,", "But behold,"], ["ua mavae atu outou,", "ye are gone,"], ["ma e le mafai e lou fanoanoa ona toe faafoisia mai outou.", "and my sorrows cannot bring your return."]]},
  {num:21,words:[["Ma e vave ona oo mai o le aso e faaoofuina ai o outou tino faaletino i le tino ola pea, ma o nei tino ua i ai nei i le pala e le pine ae avea ma tino le pala;", "And the day soon cometh that your mortal must put on immortality,"], ["ma ona tatau ai lea ona outou tutu i luma o le nofoa-faamasino o Keriso,", "and these bodies which are now moldering incorruption must soon become incorruptible bodies;"], ["e faamasinoina e tusa ma a outou galuega;", "and then ye must stand before the judgment– seat of Christ to be judged according to your works and if it so be that ye are righteous,"], ["afai e faapea ua outou amiotonu, ona faamanuiaina lea o outou faatasi ma o outou tamā o e na o muamua atu i a te outou.", "then are ye blessed with your fathers who have gone before you."]]},
  {num:22,words:[["E, pe a na outou salamo ae lei oo mai lenei faafanoga tele ia te outou.", "O that ye had repented before this great destruction had come upon you."], ["Ae faauta,", "But behold,"], ["ua outou o atu,", "ye are gone,"], ["ma ua silafia e le Tamā,", "and the Father,"], ["ioe,", "yea,"], ["le Tamā Faavavau o le lagi,", "the Eternal Father of heaven,"], ["lo outou tulaga;", "knoweth your state;"], ["ma e faia e ia ia te outou e tusa ma lona faamasinotonu ma lona alofa mutimutivale.", "and he doeth with you according to his justice and mercy."]]},
];
renderVerseSet(mm_ch_6_Verses, 'mm-ch6-verses');

var mm_ch_7_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ou te fia tautala teisi atu i le toe vaega o lenei nuu o e ua faasaoina,", "I would speak somewhat unto the remnant of this people who are spared,"], ["pe afai e faapea e tuu atu e le Atua ia te i latou au upu,", "if it so be that God may give unto them my words,"], ["ina ia mafai ona latou iloa mea e uiga i o latou tamā;", "that they may know of the things of their fathers;"], ["ioe,", "yea,"], ["ou te tautala atu ia te outou,", "I speak unto you,"], ["outou le toe vaega o le aiga o Isaraelu;", "ye remnant of the house of Israel;"], ["ma o upu nei ou te tautala atu ai:", "and these are the words which I speak:"]]},
  {num:2,words:[["Ia outou iloa o outou o le aiga o Isaraelu.", "Know ye that ye are of the house of Israel."]]},
  {num:3,words:[["Ia outou iloa e ao ina outou salamo,", "Know ye that ye must come unto repentance,"], ["a leai e le mafai ona faaolaina outou.", "or ye cannot be saved."]]},
  {num:4,words:[["Ia outou iloa e ao ina outou tuu i lalo a outou auupega o taua,", "Know ye that ye must lay down your weapons of war,"], ["ma ia le toe fiafia i le faamasaaina o le toto,", "and delight no more in the shedding of blood,"], ["ma le toe avea i latou,", "and take them not again,"], ["vagana ai e poloaiina ai outou e le Atua.", "save it be that God shall command you."]]},
  {num:5,words:[["Ia outou iloa e ao ina outou malamalama e uiga i o outou tamā,", "Know ye that ye must come to the knowledge of your fathers,"], ["ma salamo ia outou agasala uma ma amioletonu,", "and repent of all your sins and iniquities,"], ["ma talitonu ia Iesu Keriso,", "and believe in Jesus Christ,"], ["o ia o le Alo o le Atua,", "that he is the Son of God,"], ["ma sa fasiotia o ia e tagata Iutaia,", "and that he was slain by the Jews,"], ["ma ua toetu mai o ia e ala i le mana o le Tama,", "and by the power of the Father he hath  risen again,"], ["o lea ua maua ai e ia le manumalo i luga o le tuugamau;", "whereby he hath gained the victory over the grave;"], ["ma ua tofatumoanaina ai foi ia te ia le tui o le oti.", "and also in him is the sting of death swallowed up."]]},
  {num:6,words:[["Ma ua faataunuuina e ia le toetutu mai o e na oti,", "And he bringeth to pass the resurrection of the dead,"], ["o lea o le a faatu mai ai le tagata e tu i luma o lona nofoa-faamasino .", "whereby man must be raised to stand before his judgment– seat."]]},
  {num:7,words:[["Ma ua faataunuuina e ia le togiolaina o le lalolagi,", "And he hath brought to pass the redemption of the world,"], ["lea o le a tuu atu ai ia te ia o le e maua i le le sala i ona luma i le aso faamasino,", "whereby he that is found guiltless before him at the judgment day hath it given unto him to dwell in the presence of God in his kingdom,"], ["e mau i luma o le Atua i lona malo,", "to sing ceaseless praises with the choirs above,"], ["e pese viiga le motusia faatasi ma aufaipese i luga,", "unto the Father,"], ["i le Tamā, ma i le Alo,", "and unto the Son,"], ["ma i le Agaga Paia,", "and unto the Holy Ghost,"], ["o e o ni Atua ua tasi ,", "which are one God,"], ["i se tulaga o le fiafia lea ua leai se iuga.", "in a state of happiness which hath no end."]]},
  {num:8,words:[["O lea ina salamo,", "Therefore repent,"], ["ia ma ia papatiso i le suafa o Iesu,", "and be baptized in the name of Jesus,"], ["ma opogi le talalelei a Keriso, lea o le a tuu atu i o outou luma,", "and lay hold upon the gospel of Christ,"], ["e le gata i lenei talafaamaumau,", "which shall be set before you,"], ["ae i le talafaamaumau foi lea o le a oo atu i Nuuese mai tagata Iutaia,", "not only in this record but also in the record which shall come unto the Gentiles from the Jews,"], ["o se talafaamaumau lea o le a sau mai Nuuese ia te outou.", "which record shall come from the Gentiles unto you."]]},
  {num:9,words:[["Aua faauta,", "For behold,"], ["ua tusia lenei talafaamaumau mo le faamoemoe ia outou talitonu i lena;", "this is written for the intent that ye may believe that;"], ["ma afai tou te talitonu i lena, o le a outou talitonu foi i lenei;", "and if ye believe that ye will believe this also;"], ["ma afai tou te talitonu i lenei o le a outou iloa e uiga i o outou tamā,", "and if ye believe this ye will know concerning your fathers,"], ["ma galuega ofoofogia foi ia na faia i le mana o le Atua i totonu o i latou.", "and also the marvelous works which were wrought by the power of God among them."]]},
  {num:10,words:[["Ma o le a outou iloa foi o outou o se toe vaega o le fanau a Iakopo;", "And ye will also know that ye are a remnant of the seed of Jacob;"], ["o lea ua faitauina ai outou i totonu o tagata o le feagaiga muamua;", "therefore ye are numbered among the people of the first covenant;"], ["ma afai e faapea o le a outou talitonu ia Keriso,", "and if it so be that ye believe in Christ,"], ["ma papatisoina,", "and are baptized,"], ["muamua i le vai,", "first with water,"], ["ona sosoo ai lea ma le afi ma le Agaga Paia,", "then with fire and with the Holy Ghost,"], ["e mulimuli i le faataitaiga a lo tatou Faaola,", "following the example of our Savior,"], ["e tusa ma mea ua ia poloaiina ai i tatou,", "according to that which he hath commanded us,"], ["o le lelei ia te outou i le aso o le faamasinoga. Amene.", "it shall be well with you in the day of judgment. Amen."]]},
];
renderVerseSet(mm_ch_7_Verses, 'mm-ch7-verses');

var mm_ch_8_Verses = [
  {num:1,words:[["Faauta,", "Behold I,"], ["o au,", "Moroni,"], ["o Moronae , ou te faaiuina le talafaamaumau a lou tamā,", "do finish the record of my father,"], ["o Mamona.", "Mormon."], ["Faauta,", "Behold,"], ["ua ia te au ni nai mea itiiti e tusia,", "I have but few things to write,"], ["o mea ia na poloaiina ai au e lou tamā.", "which things I have been commanded by my father."]]},
  {num:2,words:[["Ma o lenei sa oo ina ua mavae le taua tele ma le matautia i Kumora,", "And now it came to pass that after the great and tremendous battle at Cumorah,"], ["faauta,", "behold, the Nephites who had escaped into the country southward were hunted by the Lamanites,"], ["o sa Nifaē o e na sosola atu i le laueleele i saute sa sailia e sa Lamanā seia oo ina faaumatiaina i latou uma.", "until they were all destroyed."]]},
  {num:3,words:[["Ma sa latou fasiotia foi lou tamā,", "And my father also was killed by them,"], ["ma ua totoe ai nao au lava e tusi le tala faanoanoa o le faaumatiaga o ou tagata. Ae faauta,", "and I even remain alone to write the sad tale of the destruction of my people. But behold,"], ["ua mavae atu i latou,", "they are gone,"], ["ma ou te faataunuuina le poloaiga a lou tamā. Ma pe latou te fasiotia au pe leai,", "and I fulfil the commandment of my father. And whether they will slay me,"], ["ou te le iloa.", "I know not."]]},
  {num:4,words:[["O lea o le a ou tusia ma natia ai talafaamaumau i le eleele;", "Therefore I will write and hide up the records in the earth;"], ["ma po o fea ou te alu i ai ua le afaina.", "and whither I go it mattereth not."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["na faia e lou tamā lenei talafaamaumau,", "my father hath made this record,"], ["ma ua ia tusia le faamoemoe na faia ai. Faauta foi,", "and he hath written the intent thereof. And behold,"], ["ou te tusia foi pe a na ou maua se avanoa i luga o papatusi ,", "I would write it also if I had room upon the plates,"], ["ae ua ou le mauaina;", "but I have not;"], ["ma ua le ia te au foi se oa,", "and ore I have none,"], ["ona ua nao au lava. Ua fasiotia lou tamā i le taua,", "for I am  alone. My father hath been slain in battle,"], ["ma tagata uma o lou aiga,", "and all my kinsfolk,"], ["ma ua leai ni au uo po o se mea ou te alu i ai;", "and I have not friends nor whither to go;"], ["ma o le a le umi e tuu ai au e le Alii ou te ola ai ou te le iloa.", "and how long the Lord will suffer that I may live I know not."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ua mavae atu tausaga e fa selau talu le afio mai o lo matou Alii ma le Faaola.", "four hundred years have passed away since the coming of our Lord and Savior."]]},
  {num:7,words:[["Faauta foi,", "And behold,"], ["ua saili e sa Lamanā ou tagata,", "the Lamanites have hunted my people,"], ["o sa Nifaē,", "the Nephites,"], ["i lalo mai lea aai i lea aai ma mai lea nofoaga i lea nofoaga,", "down from city to city and from place to place,"], ["seia oo lava ina latou le toe i ai;", "even until they are no more;"], ["ma sa matua tele lava lo latou pau ;", "and great has been their fall;"], ["ioe,", "yea,"], ["ua matua tele lava ma ofoofogia le faaumatiaga o ou tagata,", "great and marvelous is the destruction of my people,"], ["o sa Nifaē.", "the Nephites."]]},
  {num:8,words:[["Faauta foi,", "And behold,"], ["o le aao lava o le Alii na faia. Ma faauta foi,", "it is the hand of the Lord which hath done it. And behold also,"], ["ua tau sa Lamanā o le tasi ma le isi;", "the Lamanites are at war one with another;"], ["ma ua avea luga o lenei laueleele atoa ma taamilosaga faia pea lava pea e tasi o le fasioti tagata ma le faamasaa toto;", "and the whole face of this land is one continual round of murder and bloodshed;"], ["ma ua leai se tasi na te iloa le iuga o le taua.", "and no one knoweth the end of the war."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ou te le toe fai atu se isi mea e faatatau ia te i latou,", "I say no more concerning them,"], ["ona ua leai se tasi vagana ai sa Lamanā ma faomea o ola i luga o le laueleele.", "for there are none save it be the Lamanites and robbers that do exist upon the face of the land."]]},
  {num:10,words:[["Ma ua leai ni isi ua latou iloa le Atua moni vagana ai soo o Iesu,", "And there are none that do know the true God save it be the disciples of Jesus,"], ["o e sa nonofo i le laueleele seia oo ina matua tele le amioleaga o tagata sa le tuuina ai i latou e le Alii ia nonofo pea faatasi ma le nuu;", "who did tarry in the land until the wickedness of the people was so great that the Lord would not suffer them to remain with the people;"], ["ma pe o i ai i latou i luga o le laueleele pe leai ua leai se tagata na te iloaina.", "and whether they be upon the face of the land no man knoweth."]]},
  {num:11,words:[["Ae faauta,", "But behold,"], ["sa ma vaai ma lou tamā ia te i latou,", "my father and I have seen them,"], ["ma sa latou auauna mai ia te i maua.", "and they have ministered unto us."]]},
  {num:12,words:[["Ma o soo se tasi na te maua lenei talafaamaumau,", "And whoso receiveth this record,"], ["ma ia le tauleagaina ona o le lē atoatoa o i ai,", "and shall not condemn it because of the imperfections which are in it,"], ["o ia lava lea o le a ia iloaina mea silisili atu nai lo nei. Faauta,", "the same shall know of greater things than these. Behold,"], ["o au o Moronae;", "I am Moroni;"], ["ma a na mafai,", "and were it possible,"], ["po ua ou faailoa atu mea uma ia te outou.", "I would make all things known unto you."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["ou te faaiuina lou tautala atu e faatatau i lenei nuu. O au o le atalii o Mamona,", "I make an end of speaking concerning this people. I am the son of Mormon,"], ["ma o lou tamā o se e tupuga mai ia Nifae.", "and my father was a descendant of Nephi."]]},
  {num:14,words:[["Ma o au lava lea o le ua natiaina mau lenei talafaamaumau mo le Alii;", "And I am the same who hideth up this record unto the Lord;"], ["o papatusi o i ai ua leai se aoga,", "the plates thereof are of no worth,"], ["ona o le poloaiga a le Alii. Ona sa fetalai moni mai o ia e leai se tasi na te mauaina i latou ina ia maua ai le oa;", "because of the commandment of the Lord. For he truly saith that no one shall have them to get gain;"], ["ae o le talafaamaumau o i ai ua taua tele;", "but the record thereof is of great worth;"], ["ma o soo se tasi na te aumaia i le malamalama,", "and whoso shall bring it to light,"], ["o ia lea o le a faamanuiaina e le Alii.", "him will the Lord bless."]]},
  {num:15,words:[["Aua e leai se tasi e mafai ona ia maua le mana e aumai ai i le malamalama vagana ai ua tuuina mai ia te ia e le Atua;", "For none can have power to bring it to light save it be given him of God;"], ["ona ua finagalo le Atua ia faia mea ma le manatu tasi i lona mamalu,", "for God wills that it shall be done with an eye single to his glory,"], ["po o le manuia o tagata anamua ua loa ona faasalalauina tagata o le feagaiga a le Alii.", "or the welfare of the ancient and long dispersed covenant people of the Lord."]]},
  {num:16,words:[["Ma amuia lava o ia o le o le a ia aumaia lenei mea i le malamalama;", "And blessed be he that shall bring this thing to light;"], ["ona o le a 'aumaia mai le pouliuli i le malamalama,", "for it shall be brought out of darkness unto light,"], ["e tusa ma le afioga a le Atua;", "according to the word of God;"], ["ioe,", "yea,"], ["o le a aumaia i fafo o le eleele,", "it shall be brought out of the earth,"], ["ma o le a susulu atu i fafo mai le pouliuli,", "and it shall shine forth out of darkness,"], ["ma oo atu i le malamalama o tagata;", "and come unto the knowledge of the people;"], ["ma o le a faia i le mana o le Atua.", "and it shall be done by the power of God."]]},
  {num:17,words:[["Ma afai e i ai ni sese , o sese ia o le tagata.", "And if there be faults they be the faults of a man."], ["Ae faauta,", "But behold,"], ["ua matou te le iloa ni sese;", "we know no fault;"], ["e ui i lea ua silafia e le Atua mea uma;", "never theless God knoweth all things;"], ["o lea,", "therefore,"], ["o le na te tauleagaina ,", "he that condemneth,"], ["ia faaeteete o ia nei tu malaia o ia i le afi o seoli.", "let him be aware lest he shall be in danger of hell fire."]]},
  {num:18,words:[["Ma o ia e fai mai:", "And he that saith:"], ["Ia faaali mai ia te au,", "Show unto me,"], ["a leai o le a taina oe—ia faaeteete o ia nei ona poloaia le mea ua faasaina e le Alii.", "or ye shall be smitten—let him beware lest he commandeth that which is forbidden of the Lord."]]},
  {num:19,words:[["Aua faauta,", "For behold,"], ["o le e faamasino vave o le a vave ona toe faamasinoina;", "the same that judgeth rashly shall be judged rashly again;"], ["ona o le a tauia o ia e tusa ma ana galuega;", "for according to his works shall his wages be; therefore,"], ["o lea,", "he that smiteth shall be smitten again,"], ["o le e ta atu o le a toe taina o ia e le Alii.", "of the Lord."]]},
  {num:20,words:[["Faauta i le mea ua fai mai ai tusitusiga paia—ia aua i le tagata ona ta atu,", "Behold what the scripture says—man shall not smite,"], ["pe faamasino atu o ia;", "neither shall he judge;"], ["ona o le faamasinoga e a au ia,", "for judgment is mine,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["ma o le tauimasui e a au foi,", "and vengeance is mine also,"], ["ma o le a ou toe totogi atu.", "and I will repay."]]},
  {num:21,words:[["Ma o ia na te manavaina le ita ma le fetauai e faasaga i le galuega a le Alii,", "And he that shall breathe out wrath and strifes against the work of the Lord,"], ["ma faasaga i tagata o le feagaiga a le Alii o e o le aiga o Isaraelu,", "and against the covenant people of the Lord who are the house of Israel,"], ["ma e fai mai:", "and shall say:"], ["O le a matou faaumatiaina le galuega a le Alii,", "We will destroy the work of the Lord,"], ["ma e le toe manatua e le Alii lana feagaiga lea na ia faia i le aiga o Isaraelu—o ia lava lea ua tu malaia i le salaina i lalo ma lafo i le afi;", "and the Lord will not remember his covenant which he hath made unto the house of Israel—the same is in danger to be hewn down and cast into the fire;"]]},
  {num:22,words:[["Ona o le a taavavale pea i luma faamoemoega faavavau o le Alii,", "For the eternal purposes of the Lord shall roll on,"], ["seia oo ina faataunuuina ana folafolaga uma.", "until all his promises shall be fulfilled."]]},
  {num:23,words:[["Ia suesue i valoaga a Isaia .", "Search the prophecies of Isaiah."], ["Faauta,", "Behold,"], ["e le mafai ona ou tusia i latou.", "I cannot write them."], ["Ioe,", "Yea,"], ["faauta ou te fai atu ia te outou,", "behold I say unto you,"], ["o tagata paia na o e ua muamua atu ia te au,", "that those saints who have gone before me,"], ["o e na ō latou lenei laueleele,", "who have possessed this land,"], ["o le a tagi ae, ioe,", "shall cry,"], ["o le a latou tagi ae lava i le Alii mai le eleele;", "yea,"], ["ma e pei ona soifua le Alii,", "even from the dust will they cry unto the Lord;"], ["o le a ia manatua le feagaiga lea na ia faia ma i latou.", "and as the Lord liveth he will remember the covenant which he hath made with them."]]},
  {num:24,words:[["Ma ua silafia e ia a latou tatalo ,", "And he knoweth their prayers,"], ["sa faia mo o latou uso.", "that they were in behalf of their brethren."], ["Ma ua ia silafia lo latou faatuatua,", "And he knoweth their faith,"], ["ona o lona suafa sa mafai ai ona latou aveese o mauga ;", "for in his name could they remove mountains;"], ["ma o lona suafa sa mafai ona latou poloaiina ai le eleele ia luluina;", "and in his name could they cause the earth to shake;"], ["ma o le mana o lana afioga na latou poloaiina ai falepuipui ia pauu i le eleele;", "and by the power of his word did they cause prisons to tumble to the earth;"], ["ioe, e oo i le ogaumu aasa sa le mafai ona afaina ai i latou,", "yea,"], ["po o manu feai,", "even the fiery furnace could not harm them,"], ["po o gata uogo,", "neither wild beasts nor poisonous serpents,"], ["ona o le mana o lana afioga.", "because of the power of his word."]]},
  {num:25,words:[["Ma faauta,", "And behold,"], ["o a latou tatalo foi sa mo le o le a tuuina i ai e le Alii na te aumaia nei mea i luma.", "their prayers were also in behalf of him that the Lord should suffer to bring these things forth."]]},
  {num:26,words:[["Ma e leai se tasi e tatau ona fai mai o le a le oo mai nei mea,", "And no one need say they shall not come,"], ["ona o le a oo moni mai lava i latou,", "for they surely shall,"], ["aua ua fetalai mai ai le Alii;", "for the Lord hath spoken it;"], ["aua o le a o mai nei mea i fafo mai le eleele,", "for out of the earth shall they come,"], ["e ala i le aao o le Alii,", "by the hand of the Lord,"], ["ma e leai se tasi e mafai ona ia taofia;", "and none can stay it;"], ["ma o le a oo mai le aso e faapea ane ai tagata ua le toe i ai ni vavega ;", "and it shall come in a day when it shall be said that miracles are done away;"], ["ma o le a oo mai e pei o se tasi ua tautala mai nai e ua oti.", "and it shall come even as if one should speak from the dead."]]},
  {num:27,words:[["Ma o le a oo mai le aso o le a tagi atu ai le toto o le au paia i le Alii,", "And it shall come in a day when the blood of saints shall cry unto the Lord,"], ["ona o faapotopotoga faalilolilo ma galuega o le pouliuli.", "because of secret combinations and the works of darkness."]]},
  {num:28,words:[["Ioe,", "Yea,"], ["o le a oo mai le aso o le a faafitia ai le mana o le Atua,", "it shall come in a day when the power of God shall be denied,"], ["ma o le a faaleagaina ai ekalesia ma faafefeteina i luga i le faamaualuluga o o latou loto;", "and churches become defiled and be lifted up in the pride of their hearts;"], ["ioe,", "yea,"], ["i le aso lava o le a tutulai ae ai taitai ma faiaoga o ekalesia i le faamaualuluga o o latou loto,", "even in a day when leaders of  churches and teachers shall rise in the pride of their hearts,"], ["e oo i le mataua ia te i latou o e ua auai ia latou ekalesia.", "even to the envying of them who belong to their churches."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["o le a oo mai le aso o le a faalogoina ai tala i afi,", "it shall come in a day when there shall be heard of fires,"], ["ma matagi tetele,", "and tempests,"], ["ma puao o le asu i laueleele ese;", "and vapors of smoke in foreign lands;"]]},
  {num:30,words:[["Ma o le a faalogoina foi taua ,", "And there shall also be heard of wars,"], ["tala o taua,", "rumors of wars,"], ["ma mafuie i nofoaga eseese.", "and earthquakes in divers places."]]},
  {num:31,words:[["Ioe,", "Yea,"], ["o le a oo mai le aso o le a i ai le eleelea tele i luga o le lalolagi;", "it shall come in a day when there shall be great pollutions upon the face of the earth;"], ["o le a i ai le fasioti tagata,", "there shall be murders,"], ["ma le faomea,", "and robbing,"], ["ma pepelo,", "and lying,"], ["ma taufaasese,", "and deceivings,"], ["ma faitaaga,", "and whoredoms,"], ["ma mea inosia uiga eseese uma;", "and all manner of abominations;"], ["i le taimi o le a i ai le toatele o e o le a fai mai,", "when there shall be many who will say,"], ["Fai lenei,", "Do this,"], ["po o le fai lena,", "or do that,"], ["ma e le afaina,", "and it mattereth not,"], ["ona o le a lagolagoina e le Alii mea faapena i le aso gataaga.", "for the Lord will uphold such at the last day."], ["Ae oi talofa i e faapena, ona ua latou i ai i le āu oona ma noanoaga o le amioletonu.", "But wo unto such for they are in the gall of bitterness and in the bonds of iniquity."]]},
  {num:32,words:[["Ioe,", "Yea,"], ["o le a oo mai i le aso o le a i ai ekalesia e atiae o le a fai mai:", "it shall come in a day when there shall be churches built up that shall say:"], ["O mai ia te au,", "Come unto me,"], ["ma o le a faamagaloina outou ia outou agasala mo a outou tupe.", "and for your money you shall be forgiven of your sins."]]},
  {num:33,words:[["E,", "O ye wicked and perverse and stiffnecked people,"], ["outou tagata amioleaga e ma faapiopio ma ua maaa,", "why have ye built up churches unto yourselves to get gain? Why have ye transfigured the holy word of God,"], ["aisea ua outou atiae ai ekalesia mo outou lava ina ia maua ai oa ? Aisea ua outou suia ai le afioga paia a le Atua o le a mafai ona outou aumai ai o le malaia i luga o o outou agaga? Faauta,", "that ye might bring damnation upon your souls? Behold,"], ["ia outou tagatagai i faaaliga a le Atua;", "look ye unto the revelations of God;"], ["aua faauta,", "for behold,"], ["e oo mai le taimi i lena aso o le a faataunuuina ai nei mea uma.", "the time cometh at that day when all these things must be fulfilled."]]},
  {num:34,words:[["Faauta,", "Behold,"], ["ua faaali mai e le Alii ia te au mea tetele ma ofoofogia e faatatau i mea ua lata ona oo mai,", "the Lord hath shown unto me great and marvelous things concerning that which must shortly come,"], ["i lena aso o le a oo mai ai nei mea ia te outou.", "at that day when these things shall come forth among you."]]},
  {num:35,words:[["Faauta,", "Behold,"], ["ou te tautala atu ia te outou e peiseai o outou faatasi mai i le taimi nei,", "I speak unto you as if ye were present,"], ["peitai ua outou le o i ai. Ae faauta,", "and yet ye are not. But behold,"], ["ua faaali mai outou ia te au e Iesu Keriso,", "Jesus Christ hath shown you unto me,"], ["ma ua ou iloa a outou mea o fai.", "and I know your doing."]]},
  {num:36,words:[["Ma ua ou iloa ua outou savavali i le faamaualuluga o o outou loto;", "And I know that ye do walk in the pride of your hearts;"], ["ma ua leai ni isi vagana ai nao se toaitiiti o e ua le faafefeteina i latou i luga i le faamaualuluga o o latou loto,", "and there are none save a few only who do not lift themselves up in the pride of their hearts,"], ["i le ofuina o ofu mananaia tele,", "unto the wearing of very fine apparel,"], ["i le mataua,", "unto envying,"], ["ma feteenaiga,", "and strifes,"], ["ma le lotoleaga,", "and malice,"], ["ma sauaga,", "and persecutions,"], ["ma amioletonu ituaiga eseese uma;", "and all manner of iniquities;"], ["ma o a outou ekalesia,", "and your churches,"], ["ioe,", "yea,"], ["ekalesia taitasi uma lava,", "even every one,"], ["ua faaeleeleaina ona o le faamaualuluga o o outou loto.", "have become polluted because of the pride of your hearts."]]},
  {num:37,words:[["Aua faauta,", "For behold,"], ["ua sili atu lo outou alolofa i tupe ,", "ye do love money,"], ["ma a outou oloa,", "and your substance,"], ["ma o outou ofu mananaia,", "and your fine apparel,"], ["ma le teuteuina o a outou ekalesia,", "and the adorning of your churches,"], ["nai lo outou alolofa i e ua matitiva ma e ua le tagolima,", "more than ye love the poor and the needy,"], ["e ua mamai ma e ua puapuagatia.", "the sick and the afflicted."]]},
  {num:38,words:[["E,", "O ye pollutions,"], ["outou e o e ua eleelea,", "ye hypocrites,"], ["outou e o pepelo, outou o aoao,", "ye teachers,"], ["o e ua faatau atu outou lava mo mea e pala,", "who sell yourselves for that which will canker,"], ["aisea ea ua outou faaeleelea ai le ekalesia paia a le Atua? Aisea ea ua outou maasiasi ai e ave i o outou luga le suafa o Keriso? Aisea ea tou te le manatunatu ai i le sili atu o le taua o le fiafia e le gata nai lo o lena pagatia e le uma lava—ona o le viiga o le lalolagi?", "why have ye polluted the holy church of God? Why are ye ashamed to take upon you the name of Christ? Why do ye not think that greater is the value of an endless happiness than that misery which never dies—because of the praise of the world?"]]},
  {num:39,words:[["Aisea ea ua outou teuteuina ai outou lava i mea ua leai ni ola,", "Why do ye adorn yourselves with that which hath no life,"], ["ae ua outou tuu e ua fia aai,", "and yet suffer the hungry,"], ["ma e ua matitiva, ma e ua le lavalava,", "and the needy,"], ["ma e ua mamai ma puapuagatia,", "and the naked,"], ["e ui ane i o outou tafatafa,", "and the sick and the afflicted to pass by you,"], ["ma outou le amanaiaina i latou?", "and notice them not?"]]},
  {num:40,words:[["Ioe,", "Yea,"], ["aisea ua outou atiae ai a outou faapotopotoga faalilolilo e maua ai oa,", "why do ye build up your secret abominations to get gain,"], ["ma faia ia oi fafine ua oti a latou tane i luma o le Alii,", "and cause that widows should mourn before the Lord,"], ["ma fanau matuaoti foi ia faanoanoa i luma o le Alii,", "and also orphans to mourn before the Lord,"], ["ma ia tagi ae foi i le Alii mai le eleele toto o o latou tamā ma a latou tane,", "and also the blood of their fathers and their husbands to cry unto the Lord from the ground,"], ["mo le tauimasui i luga o o outou ulu?", "for vengeance upon your heads?"]]},
  {num:41,words:[["Faauta,", "Behold,"], ["ua tautau ifo le pelu o le tauimasui i o outou luga;", "the sword of vengeance hangeth over you;"], ["ma ua lata ona oo mai o le taimi o le a ia tauia ai le toto o le au paia i o outou luga,", "and the time soon cometh that he avengeth the blood of the saints upon you,"], ["ona o le a ia le toe onosaia a latou tagi.", "for he will not suffer their cries any longer."]]},
];
renderVerseSet(mm_ch_8_Verses, 'mm-ch8-verses');

var mm_ch_9_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["ou te tautala atu foi ia te i latou o e ua le talitonu ia Keriso.", "I speak also concerning those who do not believe in Christ."]]},
  {num:2,words:[["Faauta,", "Behold,"], ["pe tou te talitonu ea i le aso o lo outou asiga—faauta,", "will ye believe in the day of your visitation—behold,"], ["pe a afio mai le Alii,", "when the Lord shall come,"], ["ioe,", "yea,"], ["i lena lava aso tele pe a taataaia le lalolagi e pei o se tusitaai, ma o le a liusuavai ai elemene i le vevela tele,", "even that great day when the earth shall be rolled together as a scroll,"], ["ioe,", "and the elements shall melt with fervent heat,"], ["i lena aso tele pe a aumai outou e tutu i luma o le Tamai Mamoe a le Atua—i lena taimi,", "yea,"], ["pe o le a outou fai mai ea ua leai se Atua?", "in that great day when ye shall be brought to stand before the Lamb of God—then will ye say that there is no God?"]]},
  {num:3,words:[["Pe o le a outou le toe faafitia ea i lena taimi le Keriso,", "Then will ye longer deny the Christ,"], ["pe mafai ona outou vaai atu i le Tamai Mamoe a le Atua? Tou te manatu ea e mafai ona outou mau faatasi ma ia i lalo o lo outou iloa lelei o lo outou sala? Tou te manatu ea e mafai ona outou fiafia e mau faatasi ma lena Tagata paia,", "or can ye behold the Lamb of God? Do ye suppose that ye shall dwell with him under a consciousness of your guilt? Do ye suppose that ye could be happy to dwell with that holy Being,"], ["ao falo tiga o outou agaga i le lagona sala i lo outou solia pea o ana tulafono?", "when your souls are racked with a consciousness of guilt that ye have ever abused his laws?"]]},
  {num:4,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou o le a sili atu ona outou pagatia i le mau faatasi ma se Atua paia ma fai mea tonu,", "I say unto you that ye would be more miserable to dwell with a holy and just God,"], ["i lalo o lo outou iloa lelei o lo outou eleelea i ona luma,", "under a consciousness of your filthiness before him,"], ["nai lo lo outou mau faatasi ma agaga faasalaina i seoli .", "than ye would to dwell with the damned souls in hell."]]},
  {num:5,words:[["Aua faauta,", "For behold,"], ["pe a aumai outou tou te vaai i lo outou le lavalava i luma o le Atua,", "when ye shall be brought to see your nakedness before God,"], ["ma le mamalu foi o le Atua,", "and also the glory of God,"], ["ma le paia o Iesu Keriso,", "and the holiness of Jesus Christ,"], ["o le a tutuina e lena mea i luga o outou se afi e le matineia.", "it will kindle a flame of unquenchable fire upon you."]]},
  {num:6,words:[["O lea la outou e ua le talitonu,", "O then ye unbelieving,"], ["ia outou liliu mai i le Alii;", "turn ye unto the Lord;"], ["tagi malosi atu i le Tamā i le suafa o Iesu,", "cry mightily unto the Father in the name of Jesus,"], ["aua atonu e mafai ai ona maua o outou i le le pona,", "that perhaps ye may be found spotless,"], ["mamā ,", "pure,"], ["lalelei,", "fair,"], ["ma sinasina,", "and white,"], ["ona ua faamamaina i le toto o le Tamai Mamoe,", "having been cleansed by the blood of the Lamb,"], ["i lena aso tele ma gata ai.", "at that great and last day."]]},
  {num:7,words:[["Ma ou te toe tautala atu ia te outou o e e faafitia faaaliga a le Atua,", "And again I speak unto you who deny the revelations of God,"], ["ma fai mai ua mavae atu i latou,", "and say that they are done away,"], ["ua leai ni faaaliga,", "that there are no revelations,"], ["po o ni valoaga,", "nor prophecies,"], ["po o ni meaalofa,", "nor gifts,"], ["po o ni faamalologa,", "nor healing,"], ["po o le tautala i gagana,", "nor speaking with tongues,"], ["ma le faamatalaga o gagana;", "and the interpretation of tongues;"]]},
  {num:8,words:[["Faauta ou te fai atu ia te outou,", "Behold I say unto you,"], ["o le e faafitia nei mea ua le iloa e ia le talalelei a Keriso;", "he that denieth these things knoweth not the gospel of Christ;"], ["ioe,", "yea,"], ["e lei faitauina e ia o tusitusiga paia;", "he has not read the scriptures;"], ["afai na ia faitauina,", "if so,"], ["ua le malamalama i ai o ia.", "he does not understand them."]]},
  {num:9,words:[["Aua pe ua tatou le faitauina ea o le Atua ua tutusa lava ia o ananafi,", "For do we not read that God is the same yesterday,"], ["i le asō,", "today,"], ["ma le faavavau,", "and forever,"], ["ma ua leai se feliuliuai po o sina fesuisuiai o ia te ia?", "and in him there is no variableness neither shadow of changing?"]]},
  {num:10,words:[["Ma o lenei,", "And now if ye have imagined up unto yourselves a god who doth vary,"], ["afai ua outou mafaufau ifo ia te outou lava i se atua e feliuliuai, ma o se ua i ai sina fesuisuiai,", "and in whom there is shadow of changing,"], ["o lona uiga ua outou mafaufauina ia te outou lava se atua o le ua le o se Atua o vavega.", "then have ye imagined up unto yourselves a god who is not God of miracles."]]},
  {num:11,words:[["Ae faauta,", "But behold,"], ["o le a ou faaali atu ia te outou se Atua o vavega,", "I will show unto you a God of miracles,"], ["o le Atua lava lea o Aperaamo,", "even the God of Abraham,"], ["ma le Atua o Isaako,", "and the God of Isaac,"], ["ma le Atua o Iakopo;", "and the God of Jacob;"], ["ma o le Atua lava lea e tasi o le na foafoaina lagi ma le lalolagi,", "and it is that same God who created the heavens and the earth,"], ["ma mea uma o i ai.", "and all things that in them are."]]},
  {num:12,words:[["Faauta, na ia foafoaina Atamu,", "Behold he created Adam,"], ["ma o Atamu na oo mai ai le pau o tagata.", "and by Adam came the fall of man."], ["Ma ona o le pau o tagata na afio mai ai Iesu Keriso,", "And because of the fall of man came Jesus Christ,"], ["o le Tamā lava lea ma le Alo;", "even the Father and the Son;"], ["ma o Iesu Keriso na oo mai ai le togiolaina o tagata.", "and because of Jesus Christ came the redemption of man."]]},
  {num:13,words:[["Ma ona o le togiolaina o tagata,", "And because of the redemption of man,"], ["lea na oo mai e ala ia Iesu Keriso,", "which came by Jesus Christ,"], ["ua toe aumai ai i latou i luma o le Alii;", "they are brought back into the presence of the Lord;"], ["ioe,", "yea,"], ["o le ala lenei ua togiolaina ai tagata uma,", "this is wherein all men are redeemed,"], ["ona o le maliu o Keriso ua aumai ai le toetutu ,", "because the death of Christ bringeth to pass the resurrection,"], ["lea ua aumai ai le togiolaina mai se moe lē gata,", "which bringeth to pass a redemption from an endless sleep,"], ["le moe lea o le a fafagu mai ai tagata uma lava e le mana o le Atua pe a ilia le pu;", "from which sleep all men shall be awakened by the power of God when the trump shall sound;"], ["ma o le a latou tutu mai,", "and they shall come forth,"], ["o e maualalalo ma e silisili,", "both small and great,"], ["ma o le a tutu uma i luma o lana pa faamasino,", "and all shall stand before his bar,"], ["ua togiolaina ma ua tatala mai lenei fusi faavavau o le oti,", "being redeemed and loosed from this eternal band of death,"], ["le oti lea o se oti faaletino.", "which death is a temporal death."]]},
  {num:14,words:[["Ma ona oo mai ai lea o le faamasinoga a le Paia e Toatasi i luga o i latou;", "And then cometh the judgment of the Holy One upon them;"], ["ma ona oo mai ai lea o le taimi o le ua eleelea o le a eleelea pea;", "and then cometh the time that he that is filthy shall be filthy still;"], ["ma o le ua amiotonu o le a amiotonu pea;", "and he that is righteous shall be righteous still;"], ["o le ua fiafia o le a fiafia pea;", "he that is happy shall be happy still;"], ["ma o le ua le fiafia o le a le fiafia pea.", "and he that is unhappy shall be unhappy still."]]},
  {num:15,words:[["Ma o lenei,", "And now,"], ["outou e tagata uma o e na outou mafaufauina ia te outou lava se atua o le ua le mafai ona faia e ia o ni vavega,", "O all ye that have imagined up unto yourselves a god who can do no miracles,"], ["ou te fia fesili atu ia te outou,", "I would ask of you,"], ["po ua mavae ea nei mea uma,", "have all these things passed,"], ["ia ua ou tautala atu ai? Po ua oo mai ea le iuga? Faauta ou te fai atu ia te outou,", "of which I have spoken? Has the end come yet? Behold Isay unto you,"], ["E leai;", "Nay;"], ["ma ua lei taofia lava le avea o le Atua ma se Atua o vavega.", "and God has not ceased to be a God of miracles."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ua le ofoofogia ea i o outou mata mea ua faia e le Atua? Ioe,", "are not the things that God hath wrought marvelous in our eyes? Yea,"], ["ma o ai ea e mafai ona malamalama i galuega ofoofogia a le Atua?", "and who can comprehend the marvelous works of God?"]]},
  {num:17,words:[["O ai ea e fai mai e le o se vavega na faia ai le lagi ma le lalolagi i lana fetalaiga ;", "Who shall say that it was not a miracle that by his word the heaven and the earth should be;"], ["ma o le mana o lana fetalaiga na foafoa ai le tagata mai le efuefu o le eleele;", "and by the power of his word man was created of the dust of the earth;"], ["ma o le mana o lana fetalaiga na faia ai vavega?", "and by the power of his word have miracles been wrought?"]]},
  {num:18,words:[["Ma o ai e fai mai sa lei faia e Iesu Keriso ni vavega tetele e tele? Ma e tele vavega tetele na i ai na faia e aao o le au aposetolo.", "And who shall say that Jesus Christ did not many mighty miracles? And there were many mighty miracles wrought by the hands of the apostles."]]},
  {num:19,words:[["Ma afai sa i ai ni vavega na faia i taimi na,", "And if there were miracles wrought then,"], ["aisea ua taofia ai le Atua mai le avea ma se Atua o vavega ma avea pea ma se Tagata le feliuai? Faauta foi,", "why has God ceased to be a God of miracles and yet be an unchangeable Being? And behold,"], ["ou te fai atu ia te outou ua le feliuai o ia;", "I say unto you he changeth not;"], ["afai e feliuai o le a taofia le avea o ia ma Atua;", "if so he would cease  to be God;"], ["peitai ua le taofia le avea o ia ma Atua,", "and he ceaseth not to be God,"], ["ma o ia o se Atua o vavega.", "and is a God of miracles."]]},
  {num:20,words:[["Ma o le pogai ua taofia ai o ia mai le faia o vavega i totonu o le fanauga a tagata ona ua faaitiitia i latou i le le talitonu,", "And the reason why he ceaseth to do miracles among the children of men is because that they dwindle in unbelief,"], ["ma o ese mai le ala sao,", "and depart from the right way,"], ["ma ua latou le iloa le Atua o le e tatau ona latou faalagolago i ai.", "and know not the God in whom they should trust."]]},
  {num:21,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you that whoso believeth in Christ,"], ["soo se tasi e talitonu ia Keriso, ma lē masalosalo i se mea,", "doubting nothing,"], ["soo se mea e ole atu ai i le Tamā i le suafa o Keriso o le a tuuina mai ia te ia;", "whatsoever he shall ask the Father in the name of Christ it shall be granted him;"], ["ma o lenei folafolaga ua mo tagata uma,", "and this promise is unto all,"], ["e oo lava i tuluiga o le lalolagi.", "even unto the ends of the earth."]]},
  {num:22,words:[["Aua faauta,", "For behold,"], ["ua faapea ona fetalai mai o Iesu Keriso,", "thus said Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["i ona soo o e o le a nonofo pea,", "unto his disciples who should tarry,"], ["ioe,", "yea,"], ["ma i ona soo uma foi,", "and also to all his disciples,"], ["ao faalogo mai le motu o tagata:", "in the hearing of the multitude:"], ["Ia outou o atu ia i le lalolagi uma,", "Go ye into all the world,"], ["ma talai atu le talalelei i tagata uma;", "and preach the gospel to every creature;"]]},
  {num:23,words:[["Ma o ia o le e talitonu ma papatisoina o le a faaolaina,", "And he that believeth and is baptized shall be saved,"], ["ae o ia o le e le talitonu o le a faasalaina ;", "but he that believeth not shall be damned;"]]},
  {num:24,words:[["Ma o faailoga nei o le a mulimuli atu ia te i latou o e e talitonu—o lou igoa o le a latou tutuli ese ai tiapolo ;", "And these signs shall follow them that believe—in my name shall they cast out devils;"], ["o le a latou tautala i gagana fou;", "they shall speak with new tongues;"], ["o le a latou fetagofi i gata;", "they shall take up serpents;"], ["ma afai latou te inu i soo se mea o le a le afaina ai i latou;", "and if they drink any deadly thing it shall not hurt them;"], ["o le a latou faaee atu lima i luga o e mamai ma o le a faamaloloina i latou;", "they shall lay hands on the sick and they shall recover;"]]},
  {num:25,words:[["Ma o soo se tasi e talitonu i lou igoa,", "And whosoever shall believe in my name,"], ["ma lē masalosalo i se mea,", "doubting nothing,"], ["o ia lea o le a ou faamaonia i ai au upu uma,", "unto him will I confirm all my words,"], ["e oo lava i tuluiga o le lalolagi.", "even unto the ends of the earth."]]},
  {num:26,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["o ai e mafai ona tu tetee i galuega a le Alii? O ai e mafai ona faafitia ana fetalaiga? O ai e tu ae e tetee i le mana malosi aoao o le Alii? O ai o le a inosiaina galuega a le Alii? O ai o le a inosiaina fanau a Keriso? Faauta,", "who can stand against the works of the Lord? Who can deny his sayings? Who will rise up against the almighty power of the Lord? Who will despise the works of the Lord? Who will despise the children of Christ? Behold,"], ["outou uma o e ua inoino i galuega a le Alii,", "all ye who are despisers of the works of the Lord,"], ["ona o le a outou ofo ma fano ai.", "for ye shall wonder and perish."]]},
  {num:27,words:[["O lea ia outou le inoino,", "O then despise not,"], ["ma le ofo,", "and wonder not,"], ["ae ia faalogo i afioga a le Alii,", "but hearken unto the words of the Lord,"], ["ma ole atu i le Tamā i le suafa o Iesu mo soo se mea tou te manaomia. Aua le masalosalo,", "and ask the Father in the name of Jesus for what things soever ye shall stand in need. Doubt not,"], ["ae ia talitonu,", "but be believing,"], ["ma amata e pei o taimi anamua,", "and begin as in times of old,"], ["ma o mai i le Alii ma o outou loto atoa,", "and come unto the Lord with all your heart,"], ["ma galueaiina o outou lava olataga i le matau ma le gatete i ona luma.", "and work out your own salvation with fear and trembling before him."]]},
  {num:28,words:[["Ia outou popoto i aso o lo outou vaavaaiga;", "Be wise in the days of your probation;"], ["tafi ese mai ia te outou mea le mama uma;", "strip yourselves of all uncleanness;"], ["aua le ole atu i se mea,", "ask not,"], ["ina ia mafai ona outou faamaumauina i o outou tuinanauga ,", "that ye may consume it on your lusts,"], ["ae ia ole atu ma le mausali le maluelueina,", "but ask with a firmness unshaken,"], ["ina ia outou le gauai atu i se faaosoosoga,", "that ye will yield to no temptation,"], ["ae o le a outou auauna atu i le Atua moni ma soifua.", "but that ye will serve the true and living God."]]},
  {num:29,words:[["Vaai ia le papatisoina outou ma le le agavaa;", "See that ye are not baptized unworthily;"], ["vaai ia outou le taumamafa i le faamanatuga o Keriso ma le faaletatau ;", "see that ye partake not of the sacrament of Christ unworthily;"], ["ae vaai ia outou faia mea uma ma le agavaa ,", "but see that ye do all things in worthiness,"], ["ma ia faia i le suafa o Iesu Keriso,", "and do it in the name of Jesus Christ,"], ["le Alo o le Atua soifua;", "the Son of the living God;"], ["ma afai tou te faia lenei mea,", "and if ye do this,"], ["ma tumau e oo i le iuga,", "and endure to the end,"], ["o le a leai lava se ala o le a tutulia ai outou i fafo.", "ye will in nowise be cast out."]]},
  {num:30,words:[["Faauta,", "Behold,"], ["ou te tautala atu ia te outou e peiseai ua ou tautala atu mai e ua oti;", "I speak unto you as though I spake from the dead;"], ["ona ua ou iloa o le a outou mauaina au upu.", "for I know that ye shall have my words."]]},
  {num:31,words:[["Aua tou te tauleagaina au ona o ou le atoatoa,", "Condemn me not because of mine imperfection,"], ["po o lou tamā,", "neither my father,"], ["ona o ona le atoatoa, po o i latou o e na tusitusi muamua atu ia te ia;", "because of his imperfection,"], ["ae nai lo lena,", "neither them who have written before him;"], ["ia outou avatu le faafetai i le Atua ina ua ia faaalia atu ia te outou o matou le atoatoa,", "but rather give thanks unto God that he hath made manifest unto you our imperfections,"], ["ina ia outou aoao ia sili atu ona outou popoto nai lo i matou.", "that ye may learn to be more wise than we have been."]]},
  {num:32,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ua matou tusia lenei talafaamaumau e tusa ma lo matou iloa,", "we have written this record according to our knowledge,"], ["i mataitusi ua taua i totonu o i matou o le faa-Aikupito liua ,", "in the characters which are called among us there formed Egyptian,"], ["lea na tuulima faasolo mai ma matou suia,", "being handed down and altered by us,"], ["e tusa ma la matou gagana.", "according to our manner of speech."]]},
  {num:33,words:[["Ma a na fai e lava le tetele o a matou papatusi po ua matou tusitusi i le gagana Eperu;", "And if our plates had been sufficiently large we should have written in Hebrew;"], ["peitai sa matou suia foi le gagana Eperu;", "but the Hebrew hath been altered by us also;"], ["ma a na mafai ona matou tusi i le gagana a Eperu,", "and if we could have written in Hebrew,"], ["faauta,", "behold,"], ["po ua outou le maua se le atoatoa i la matou talafaamaumau.", "ye would have had no imperfection in our record."]]},
  {num:34,words:[["Peitai ua silafia e le Alii mea ua matou tusia,", "But the Lord knoweth the things which we have written,"], ["ma ua leai foi ni isi tagata latou te iloaina la matou gagana;", "and also that none other people knoweth our language;"], ["ma ona ua leai ni isi tagata latou te iloaina la matou gagana,", "and because that none other people knoweth our language,"], ["o lea ua ia saunia ai ala mo lo latou faaliliuga.", "therefore he hath prepared means for the interpretation thereof."]]},
  {num:35,words:[["Ma ua tusia nei mea ina ia mafai ona matou aveese o matou ofu mai le toto o o matou uso,", "And these things are written that we may rid our garments of the blood of our brethren,"], ["o e ua faaitiitia i le le talitonu.", "who have dwindled in unbelief."]]},
  {num:36,words:[["Faauta foi,", "And behold,"], ["o nei mea ua matou mananao ai e uiga i o matou uso,", "these things which we have desired concerning our brethren,"], ["ioe,", "yea,"], ["lo latou toefuataiga lava lea i le malamalama ia Keriso,", "even their restoration to the knowledge of Christ,"], ["ua tusa ai ma talosaga a le au paia uma o e na mau i le laueleele.", "are according to the prayers of all the saints who have dwelt in the land."]]},
  {num:37,words:[["Ma talosia ia tuuina mai e le Alii o Iesu Keriso,", "And may the Lord Jesus Christ grant that their prayers may be answered according to their faith;"], ["ia talia a latou talosaga e tusa ma lo latou faatuatua;", "and may God the Father remember the covenant which he hath made with the house of Israel;"], ["ma talosia ia manatua e le Atua le Tamā le feagaiga lea na ia osia ma le aiga o Isaraelu; ma talosia ia faamanuiaina i latou e ia e faavavau,", "and may he bless them forever,"], ["e ala i le faatuatua i le suafa o Iesu Keriso.", "through faith on the name of Jesus Christ."], ["Amene.", "Amen."]]},
];
renderVerseSet(mm_ch_9_Verses, 'mm-ch9-verses');

